def generate(numRows):
    tri = [[1]]
    for i in range(1, numRows):
        row = [1]
        for j in range(1, i):
            row.append(tri[i-1][j-1] + tri[i-1][j])
        row.append(1)
        tri.append(row)
    return tri

def getRow(rowIndex):
    row = [1] * (rowIndex + 1)
    for i in range(1, rowIndex + 1):
        for j in range(i-1, 0, -1):
            row[j] += row[j-1]
    return row

from functools import lru_cache
@lru_cache(None)
def dp(n):
    if n == 1: return 0
    res = n - 1                    # subtract 1 repeatedly
    if n % 2 == 0: res = min(res, 1 + dp(n // 2))
    if n % 3 == 0: res = min(res, 1 + dp(n // 3))
    return res

def champagneTower(poured, query_row, query_glass):
    cup = [[0.0] * (i+1) for i in range(query_row + 2)]
    cup[0][0] = poured
    for i in range(query_row):
        for j in range(i+1):
            overflow = max(0, cup[i][j] - 1)
            cup[i+1][j]   += overflow / 2
            cup[i+1][j+1] += overflow / 2
    return min(1.0, cup[query_row][query_glass])

