def rob(nums):
    if len(nums) == 1: return nums[0]
    def robLine(arr):
        prev2, prev1 = 0, 0
        for x in arr:
            prev2, prev1 = prev1, max(prev1, prev2 + x)
        return prev1
    return max(robLine(nums[:-1]), robLine(nums[1:]))

def maxSizeSlices(slices):
    # Choose k non-adjacent from circular array of 3k elements; k = len//3
    n = len(slices); k = n // 3
    def dp(arr):
        m = len(arr)
        # dp[i][j] = max sum choosing j non-adjacent from arr[0..i]
        f = [[0]*(k+1) for _ in range(m+1)]
        for i in range(1, m+1):
            for j in range(1, k+1):
                f[i][j] = f[i-1][j]
                if i >= 2:
                    f[i][j] = max(f[i][j], f[i-2][j-1] + arr[i-1])
                elif i == 1:
                    f[i][j] = max(f[i][j], arr[0])
        return f[m][k]
    return max(dp(slices[:-1]), dp(slices[1:]))

