def boundedKnapsack(weights, values, counts, W):
    # Binary grouping: split count c into 1,2,4,...,remainder
    items = []
    for w, v, c in zip(weights, values, counts):
        k = 1
        while k <= c:
            items.append((w * k, v * k))
            c -= k; k *= 2
        if c > 0:
            items.append((w * c, v * c))
    dp = [0] * (W + 1)
    for w, v in items:
        for j in range(W, w-1, -1):
            dp[j] = max(dp[j], dp[j-w] + v)
    return dp[W]

# Variant: can you form sum S with exactly count[i] of each num?
def canPartitionKSubsets(nums, k):
    total = sum(nums)
    if total % k: return False
    target = total // k
    nums.sort(reverse=True)
    used = [False] * len(nums)
    def bt(k, start, cur):
        if k == 0: return True
        if cur == target: return bt(k-1, 0, 0)
        for i in range(start, len(nums)):
            if not used[i] and cur + nums[i] <= target:
                used[i] = True
                if bt(k, i+1, cur + nums[i]): return True
                used[i] = False
                if cur == 0: break
        return False
    return bt(k, 0, 0)

