    # Build string of length n by typing (cost_type each) or pasting clipboard (cost_paste)
    # dp[i] = min cost to get string of length i on screen
    n = len(s)
    dp = [float('inf')] * (n + 1)
    dp[0] = 0
    for i in range(1, n + 1):
        dp[i] = dp[i-1] + cost_type       # type one character
        for j in range(1, i):             # paste: had j chars, paste to get i
