def minStepsTypeA(n):
    # Ctrl-A, Ctrl-C then paste: find factor decomposition
    dp = list(range(n + 1))
    for i in range(2, n + 1):
        for j in range(1, i // 2 + 1):
            if i % j == 0:
                dp[i] = min(dp[i], dp[j] + i // j)
    return dp[n]

def shoppingOffers(price, special, needs):
    from functools import lru_cache
    n = len(price)
    @lru_cache(None)
    def dp(state):
        # base: buy each item individually
        res = sum(state[i] * price[i] for i in range(n))
        for offer in special:
            new_state = list(state)
            valid = True
            for i in range(n):
                new_state[i] -= offer[i]
                if new_state[i] < 0:
                    valid = False; break
            if valid:
                res = min(res, offer[-1] + dp(tuple(new_state)))
        return res
    return dp(tuple(needs))

