def shortestSuperstring(words):
    n = len(words)
    # Precompute overlap: how much of words[j] overlaps suffix of words[i]
    overlap = [[0]*n for _ in range(n)]
    for i in range(n):
        for j in range(n):
            if i != j:
                m = min(len(words[i]), len(words[j]))
                for k in range(m, 0, -1):
                    if words[i].endswith(words[j][:k]):
                        overlap[i][j] = k; break
    # dp[mask][i] = min total length, last word = i
    INF = float('inf')
    dp  = [[INF]*n for _ in range(1<<n)]
    par = [[-1]*n  for _ in range(1<<n)]
    for i in range(n): dp[1<<i][i] = len(words[i])
    for mask in range(1, 1<<n):
        for last in range(n):
            if not (mask >> last & 1): continue
            if dp[mask][last] == INF:  continue
            for nxt in range(n):
                if mask >> nxt & 1: continue
                nmask = mask | (1<<nxt)
                val = dp[mask][last] + len(words[nxt]) - overlap[last][nxt]
                if val < dp[nmask][nxt]:
                    dp[nmask][nxt] = val
                    par[nmask][nxt] = last
    full = (1<<n) - 1
    last = min(range(n), key=lambda i: dp[full][i])
    # reconstruct
    path = []
    mask = full
    while last != -1:
        path.append(last)
        prev = par[mask][last]
        mask ^= (1 << last)
        last = prev
    path.reverse()
    res = words[path[0]]
    for k in range(1, len(path)):
        res += words[path[k]][overlap[path[k-1]][path[k]]:]
    return res

