def minimumMountainRemovals(nums):
    import bisect
    n = len(nums)
    def lis_ending(arr):
        tails, dp = [], [0]*len(arr)
        for i, x in enumerate(arr):
            pos = bisect.bisect_left(tails, x)
            dp[i] = pos + 1
            if pos == len(tails): tails.append(x)
            else: tails[pos] = x
        return dp
    left  = lis_ending(nums)
    right = lis_ending(nums[::-1])[::-1]
    ans = 0
    for i in range(1, n-1):
        if left[i] > 1 and right[i] > 1:
            ans = max(ans, left[i] + right[i] - 1)
    return n - ans

