def minimumMoves(s):
    n = len(s)
    dp = [[0]*n for _ in range(n)]
    for i in range(n): dp[i][i] = 1
    for length in range(2, n+1):
        for i in range(n - length + 1):
            j = i + length - 1
            if length == 2:
                dp[i][j] = 1 if s[i]==s[j] else 2
            else:
                dp[i][j] = dp[i+1][j] + 1  # remove s[i] alone
                if s[i] == s[j]:
                    dp[i][j] = min(dp[i][j], dp[i+1][j-1] if i+1<=j-1 else 0)
                for k in range(i+1, j):
                    dp[i][j] = min(dp[i][j], dp[i][k] + dp[k+1][j])
    return dp[0][n-1]

def minInsertionsPalindrome(s):
