def uniquePathsWithObstacles(grid):
    m, n = len(grid), len(grid[0])
    dp = [[0]*n for _ in range(m)]
    for i in range(m):
        if grid[i][0]: break
        dp[i][0] = 1
    for j in range(n):
        if grid[0][j]: break
        dp[0][j] = 1
    for i in range(1, m):
        for j in range(1, n):
            if not grid[i][j]:
                dp[i][j] = dp[i-1][j] + dp[i][j-1]
    return dp[-1][-1]

def minPathSumWithKeys(grid):
    # dp[r][c][keys_bitmask] = min cost
    from collections import defaultdict
    import heapq
    m, n = len(grid), len(grid[0])
    dist = defaultdict(lambda: float('inf'))
    dist[(0,0,0)] = 0
    heap = [(0,0,0,0)]
    while heap:
        d, r, c, keys = heapq.heappop(heap)
        if (r,c,keys) in dist and d > dist[(r,c,keys)]: continue
        for dr,dc in [(-1,0),(1,0),(0,-1),(0,1)]:
            nr,nc = r+dr, c+dc
            if 0<=nr<m and 0<=nc<n:
                nkeys = keys  # update based on grid[nr][nc]
                nd = d + 1
                if nd < dist[(nr,nc,nkeys)]:
                    dist[(nr,nc,nkeys)] = nd
                    heapq.heappush(heap,(nd,nr,nc,nkeys))
    return min(v for (r,c,_),v in dist.items() if r==m-1 and c==n-1)

def shortestPath(grid, k):
    # BFS with state (row, col, remaining_eliminations)
    from collections import deque
    m, n = len(grid), len(grid[0])
    if k >= m+n-2: return m+n-2
    queue = deque([(0, 0, 0, k)])  # steps, r, c, k_remaining
    seen = set([(0, 0, k)])
    while queue:
        steps, r, c, rem = queue.popleft()
        for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
            nr, nc = r+dr, c+dc
            if 0<=nr<m and 0<=nc<n:
                nrem = rem - grid[nr][nc]
                if nrem >= 0 and (nr,nc,nrem) not in seen:
                    if nr==m-1 and nc==n-1: return steps+1
                    seen.add((nr,nc,nrem))
                    queue.append((steps+1,nr,nc,nrem))
    return -1

def minFallingPathSum(matrix):
    n = len(matrix)
    dp = matrix[0][:]
    for i in range(1, n):
        ndp = [0]*n
        for j in range(n):
            best = dp[j]
            if j > 0:   best = min(best, dp[j-1])
            if j < n-1: best = min(best, dp[j+1])
            ndp[j] = matrix[i][j] + best
        dp = ndp
    return min(dp)

def cherryPickup(grid):
    n = len(grid)
    from functools import lru_cache
    @lru_cache(None)
    def dp(r1, c1, r2):
        c2 = r1 + c1 - r2
        if r1>=n or c1>=n or r2>=n or c2>=n: return -float('inf')
        if r1==n-1 and c1==n-1: return grid[r1][c1]
        if grid[r1][c1]==-1 or grid[r2][c2]==-1: return -float('inf')
        cherries = grid[r1][c1] + (grid[r2][c2] if r2!=r1 else 0)
        best = max(dp(r1+1,c1,r2+1), dp(r1,c1+1,r2),
                   dp(r1+1,c1,r2),   dp(r1,c1+1,r2+1))
        if best == -float('inf'): return -float('inf')
        return cherries + best
    return max(0, dp(0, 0, 0))

def cherryPickupII(grid):
    m, n = len(grid), len(grid[0])
    from functools import lru_cache
    @lru_cache(None)
    def dp(r, c1, c2):
        if r == m: return 0
        cherries = grid[r][c1] + (grid[r][c2] if c1!=c2 else 0)
        best = 0
        for dc1 in [-1,0,1]:
            for dc2 in [-1,0,1]:
                nc1, nc2 = c1+dc1, c2+dc2
                if 0<=nc1<n and 0<=nc2<n:
                    best = max(best, dp(r+1, nc1, nc2))
        return cherries + best
    return dp(0, 0, n-1)

