def strangePrinter(s):
    n = len(s)
    dp = [[0]*n for _ in range(n)]
    for i in range(n): dp[i][i] = 1
    for length in range(2, n+1):
        for i in range(n-length+1):
            j = i+length-1
            dp[i][j] = dp[i+1][j] + 1   # print s[i] alone first
            for k in range(i+1, j+1):
                if s[k] == s[i]:
                    # extend i's print turn to cover k
                    val = (dp[i+1][k-1] if i+1<=k-1 else 0) + dp[k][j]
                    dp[i][j] = min(dp[i][j], val)
    return dp[0][n-1]

def removeBoxes(boxes):
    from functools import lru_cache
    @lru_cache(None)
    def dp(l, r, k):
        if l > r: return 0
        while l < r and boxes[r] == boxes[r-1]: r -= 1; k += 1
        res = dp(l, r-1, 0) + (k+1)**2
        for i in range(l, r):
            if boxes[i] == boxes[r]:
                res = max(res, dp(i+1, r-1, 0) + dp(l, i, k+1))
        return res
    return dp(0, len(boxes)-1, 0)

