def longestPathDAG(n, edges):
    from collections import defaultdict, deque
    graph = defaultdict(list)
    indegree = [0] * n
    for u, v in edges:
        graph[u].append(v)
        indegree[v] += 1
    dp = [1] * n
    queue = deque(i for i in range(n) if indegree[i] == 0)
    topo = []
    while queue:
        node = queue.popleft()
        topo.append(node)
        for nb in graph[node]:
            indegree[nb] -= 1
            if indegree[nb] == 0:
                queue.append(nb)
    for u in topo:
        for v in graph[u]:
            dp[v] = max(dp[v], dp[u] + 1)
    return max(dp)

