def colorTheGrid(m, n):
    MOD = 10**9+7
    from itertools import product
    # Generate valid column patterns (no two adjacent same color)
    def valid_col(pat):
        return all(pat[i] != pat[i+1] for i in range(len(pat)-1))
    cols = [p for p in product(range(3), repeat=m) if valid_col(p)]
    # Two columns compatible if no row has same color
    def compat(a, b):
        return all(a[i] != b[i] for i in range(m))
    dp = {c: 1 for c in cols}
    for _ in range(n-1):
        ndp = {c: 0 for c in cols}
        for c in cols:
            for pc in cols:
                if compat(pc, c):
                    ndp[c] = (ndp[c] + dp[pc]) % MOD
        dp = ndp
    return sum(dp.values()) % MOD

