def maximumStrongPairXor(nums):
    # Trie-based max XOR with |x-y|<=min(x,y) constraint
    nums.sort()
    class TrieNode:
        def __init__(self): self.ch=[None,None]; self.min_val=float('inf')
    root = TrieNode()
    def insert(x):
        cur = root
        for bit in range(19,-1,-1):
            b = (x>>bit)&1
            if not cur.ch[b]: cur.ch[b]=TrieNode()
            cur = cur.ch[b]
            cur.min_val = min(cur.min_val, x)
    def query(x):
        cur = root; res = 0
        for bit in range(19,-1,-1):
            b = (x>>bit)&1
            want = 1-b
            if cur.ch[want] and cur.ch[want].min_val <= x:
                res |= (1<<bit); cur = cur.ch[want]
            elif cur.ch[b]: cur = cur.ch[b]
            else: break
        return res
    ans = l = 0
    for r, y in enumerate(nums):
        insert(y)
        while nums[l] * 2 < nums[r]: l += 1  # remove too-small
        ans = max(ans, query(y))
    return ans

