def digitsSum(n, target):
    # Count integers in [1,n] whose digit sum equals target
    s = str(n)
    from functools import lru_cache
    @lru_cache(None)
    def dp(pos, rem, tight, started):
        if rem < 0: return 0
        if pos == len(s): return 1 if (started and rem==0) else 0
        limit = int(s[pos]) if tight else 9
        res = dp(pos+1, rem, False, False) if not started else 0
        for d in range(0 if not started else 0, limit+1):
            if not started and d==0:
                res += dp(pos+1, rem, False, False)
            else:
                new_t = tight and d==limit
                res += dp(pos+1, rem-d, new_t, True)
        return res
    # Simpler version using string of n
    @lru_cache(None)
    def solve(i, cur_sum, tight, started):
        if i == len(s): return int(started and cur_sum==target)
        limit = int(s[i]) if tight else 9
        ans = 0
        for d in range(0, limit+1):
            if not started and d==0:
                ans += solve(i+1, 0, False, False)
            else:
                ans += solve(i+1, cur_sum+d, tight and d==limit, True)
        return ans
    return solve(0, 0, True, False)

