def sumSubarrayMins(arr):
    MOD = 10**9+7
    n = len(arr)
    left  = [0]*n  # distance to previous smaller (strict)
    right = [0]*n  # distance to next smaller or equal
    stack = []
    for i in range(n):
        while stack and arr[stack[-1]] >= arr[i]: stack.pop()
        left[i] = i - stack[-1] if stack else i + 1
        stack.append(i)
    stack = []
    for i in range(n-1,-1,-1):
        while stack and arr[stack[-1]] > arr[i]: stack.pop()
        right[i] = stack[-1] - i if stack else n - i
        stack.append(i)
    return sum(arr[i]*left[i]*right[i] for i in range(n)) % MOD

def sumSubarrayRanges(nums):
    # Sum of (max-min) for all subarrays = sumSubarrayMaxs - sumSubarrayMins
    def contribution(arr, is_max):
        n = len(arr)
        left = right = [0]*n
        stack = []
        left_arr = [0]*n
        for i in range(n):
            cmp = (lambda a,b: a <= b) if is_max else (lambda a,b: a >= b)
            while stack and cmp(arr[stack[-1]], arr[i]): stack.pop()
            left_arr[i] = i - stack[-1] if stack else i+1
            stack.append(i)
        right_arr = [0]*n; stack = []
        for i in range(n-1,-1,-1):
            cmp = (lambda a,b: a < b) if is_max else (lambda a,b: a > b)
            while stack and cmp(arr[stack[-1]], arr[i]): stack.pop()
            right_arr[i] = stack[-1]-i if stack else n-i
            stack.append(i)
        return sum(arr[i]*left_arr[i]*right_arr[i] for i in range(n))
    return contribution(nums, True) - contribution(nums, False)

def numberOfSubarraysWithOddCount(nums, k):
    def atMost(k):
        count = res = left = 0
        for right, x in enumerate(nums):
            count += x % 2
            while count > k: count -= nums[left]%2; left+=1
            res += right - left + 1
        return res
    return atMost(k) - atMost(k-1)

def countSubarraysWithKDistinct(nums, k):
    def atMostK(k):
        freq = {}; left = res = 0
        for right, x in enumerate(nums):
            freq[x] = freq.get(x,0)+1
            while len(freq) > k:
                freq[nums[left]] -= 1
                if freq[nums[left]]==0: del freq[nums[left]]
                left += 1
            res += right - left + 1
        return res
    return atMostK(k) - atMostK(k-1)

