        stack = [-1]; res = 0
        for i, x in enumerate(h):
            while stack[-1]!=-1 and h[stack[-1]]>=x:
                height=h[stack.pop()]; width=i-stack[-1]-1; res=max(res,height*width)
            stack.append(i)
