    # dp[i][j] = min cost to split grid[0..i][0..j] into k*k pieces
    # General: DP over cut positions
    m, n = len(grid), len(grid[0])
    prefix = [[0]*(n+1) for _ in range(m+1)]
    for i in range(m):
        for j in range(n):
            prefix[i+1][j+1] = grid[i][j]+prefix[i][j+1]+prefix[i+1][j]-prefix[i][j]
    def rect_sum(r1,c1,r2,c2):
        return prefix[r2+1][c2+1]-prefix[r1][c2+1]-prefix[r2+1][c1]+prefix[r1][c1]
    from functools import lru_cache
    @lru_cache(None)
    def dp(r1,c1,r2,c2):
        if r2-r1+1==k and c2-c1+1==k: return 0
        res=float('inf')
        for r in range(r1,r2):
            res=min(res, dp(r1,c1,r,c2)+dp(r+1,c1,r2,c2)+rect_sum(r1,c1,r,c2))
        for c in range(c1,c2):
            res=min(res, dp(r1,c1,r2,c)+dp(r1,c+1,r2,c2)+rect_sum(r1,c1,r2,c))
        return res
    return dp(0,0,m-1,n-1)

