def numDistinct(s, t):
    m, n = len(s), len(t)
    dp = [[0]*(n+1) for _ in range(m+1)]
    for i in range(m+1): dp[i][0] = 1  # empty t matched in any prefix
    for i in range(1, m+1):
        for j in range(1, n+1):
            dp[i][j] = dp[i-1][j]
            if s[i-1] == t[j-1]:
                dp[i][j] += dp[i-1][j-1]
    return dp[m][n]

def isSubsequence(s, t):
    i = 0
    for c in t:
        if i < len(s) and c == s[i]: i += 1
    return i == len(s)

def countDistinctSubsequences(s):
    # Count all distinct subsequences of s
    MOD = 10**9+7
    dp = [1]  # empty subsequence
    last = {}
    for c in s:
        new = 2*sum(dp) % MOD
        if c in last: new = (new - last[c]) % MOD
        last[c] = sum(dp) % MOD
        dp.append(new - dp[-1])
    return (sum(dp) - 1) % MOD  # -1 to exclude empty

def minDistance(word1, word2):
    m, n = len(word1), len(word2)
    dp = list(range(n+1))
    for i in range(1, m+1):
        prev = dp[0]; dp[0] = i
        for j in range(1, n+1):
            temp = dp[j]
            if word1[i-1] == word2[j-1]:
                dp[j] = prev
            else:
                dp[j] = 1 + min(prev, dp[j], dp[j-1])
            prev = temp
    return dp[n]

def minDistanceOneOp(word1, word2):
    # Only delete allowed
    m, n = len(word1), len(word2)
    lcs_len = [[0]*(n+1) for _ in range(m+1)]
    for i in range(1,m+1):
        for j in range(1,n+1):
            if word1[i-1]==word2[j-1]: lcs_len[i][j]=lcs_len[i-1][j-1]+1
            else: lcs_len[i][j]=max(lcs_len[i-1][j],lcs_len[i][j-1])
    lcs = lcs_len[m][n]
    return (m-lcs)+(n-lcs)

def getLengthOfOptimalCompression(s, k):
    from functools import lru_cache
    n = len(s)
    @lru_cache(None)
    def dp(i, last, last_cnt, rem):
        if rem < 0: return float('inf')
        if i == n: return 0
        # Delete s[i]
        res = dp(i+1, last, last_cnt, rem-1)
        # Keep s[i]
        if s[i] == last:
            inc = 1 if last_cnt in (1, 9, 99) else 0
            res = min(res, inc + dp(i+1, last, last_cnt+1, rem))
        else:
            res = min(res, 1 + dp(i+1, s[i], 1, rem))
        return res
    return dp(0, '', 0, k)

def encodeLen(count):
