def soupServings(n):
    import math
    from functools import lru_cache
    # For large n, answer converges to 1.0
    if n >= 4800: return 1.0
    n = math.ceil(n / 25)
    @lru_cache(None)
    def dp(a, b):
        if a <= 0 and b <= 0: return 0.5
        if a <= 0: return 1.0
        if b <= 0: return 0.0
        return 0.25 * (dp(a-4,b) + dp(a-3,b-1) + dp(a-2,b-2) + dp(a-1,b-3))
    return dp(n, n)

def probabilityOfHeads(prob, target):
    # dp[i][j] = prob of j heads after i flips
    n = len(prob)
    dp = [0.0] * (n+1)
    dp[0] = 1.0
    for p in prob:
        for j in range(n, 0, -1):
            dp[j] = dp[j]*(1-p) + dp[j-1]*p
        dp[0] *= (1-p)
    return dp[target]

def knightProbability(n, k, row, col):
    moves = [(-2,-1),(-2,1),(-1,-2),(-1,2),(1,-2),(1,2),(2,-1),(2,1)]
    dp = [[0.0]*n for _ in range(n)]
    dp[row][col] = 1.0
    for _ in range(k):
        ndp = [[0.0]*n for _ in range(n)]
        for r in range(n):
            for c in range(n):
                if dp[r][c] == 0: continue
                for dr,dc in moves:
                    nr,nc=r+dr,c+dc
                    if 0<=nr<n and 0<=nc<n:
                        ndp[nr][nc] += dp[r][c]/8
        dp = ndp
    return sum(sum(row) for row in dp)

