def countVowelPermutation(n):
    MOD = 10**9+7
    # a→e, e→a/i, i→a/e/o/u, o→i/u, u→a
    a=e=i=o=u=1
    for _ in range(n-1):
        a,e,i,o,u = (e+i+u)%MOD, (a+i)%MOD, (e+o)%MOD, i%MOD, (i+o)%MOD
    return (a+e+i+o+u)%MOD

def countTexts(pressedKeys):
    MOD = 10**9+7
    n = len(pressedKeys)
    dp = [0]*(n+1); dp[0]=1
    for i in range(1, n+1):
        dp[i] = dp[i-1]
        if i>=2 and pressedKeys[i-1]==pressedKeys[i-2]:
            dp[i] = (dp[i]+dp[i-2])%MOD
        if i>=3 and pressedKeys[i-1]==pressedKeys[i-2]==pressedKeys[i-3]:
            dp[i] = (dp[i]+dp[i-3])%MOD
        # For 7,9 keys (4 letters): also add dp[i-4] if 4 same
        if i>=4 and pressedKeys[i-1] in '79' and len(set(pressedKeys[i-4:i]))==1:
            dp[i] = (dp[i]+dp[i-4])%MOD
    return dp[n]

def eraseOverlapIntervals(intervals):
    intervals.sort(key=lambda x: x[1])
    end = float('-inf')
    count = 0
    for s, e in intervals:
        if s >= end:
            end = e
        else:
            count += 1  # must remove this interval
    return count

def minMeetingRooms(intervals):
    import heapq
    intervals.sort()
    heap = []  # min-heap of end times (active rooms)
    for s, e in intervals:
        if heap and heap[0] <= s:
            heapq.heapreplace(heap, e)  # reuse room
        else:
            heapq.heappush(heap, e)     # new room
    return len(heap)

def videoStitching(clips, time):
    clips.sort()
    count = end = farthest = 0
    i = 0
    while end < time:
        while i < len(clips) and clips[i][0] <= end:
            farthest = max(farthest, clips[i][1])
            i += 1
        if farthest == end:
            return -1       # gap, cannot cover
        end = farthest
        count += 1
    return count

def findContentChildren(g, s):
    g.sort(); s.sort()
    i = j = 0
    while i < len(g) and j < len(s):
        if s[j] >= g[i]:
            i += 1      # child satisfied
        j += 1
    return i

def twoCitySchedCost(costs):
    costs.sort(key=lambda x: x[0] - x[1])
    n = len(costs) // 2
    return sum(c[0] for c in costs[:n]) + sum(c[1] for c in costs[n:])

def largestSumAfterKNegations(nums, k):
    nums.sort(key=abs, reverse=True)
    for i in range(len(nums)):
        if nums[i] < 0 and k > 0:
            nums[i] = -nums[i]; k -= 1
    if k % 2 == 1:
        nums[-1] = -nums[-1]    # smallest abs at end after sort
    return sum(nums)

def advantageCount(nums1, nums2):
    from sortedcontainers import SortedList
    sl = SortedList(nums1)
    res = []
    for v in nums2:
        idx = sl.bisect_right(v)
        if idx < len(sl):
            res.append(sl.pop(idx))     # beat it
        else:
            res.append(sl.pop(0))       # waste smallest
    return res

def numRescueBoats(people, limit):
    people.sort()
    l, r = 0, len(people) - 1
    boats = 0
    while l <= r:
        if people[l] + people[r] <= limit:
            l += 1
        r -= 1
        boats += 1
    return boats

def canJump(nums):
    max_reach = 0
    for i, v in enumerate(nums):
        if i > max_reach:
            return False
        max_reach = max(max_reach, i + v)
    return True

def furthestBuilding(heights, bricks, ladders):
    import heapq
    heap = []   # min-heap of ladder-assigned climbs
    for i in range(len(heights) - 1):
        diff = heights[i+1] - heights[i]
        if diff <= 0:
            continue
        heapq.heappush(heap, diff)
        if len(heap) > ladders:
            bricks -= heapq.heappop(heap)   # use bricks for cheapest ladder use
        if bricks < 0:
            return i
    return len(heights) - 1

def candy(ratings):
    n = len(ratings)
    candies = [1] * n
    for i in range(1, n):
        if ratings[i] > ratings[i-1]:
            candies[i] = candies[i-1] + 1
    for i in range(n-2, -1, -1):
        if ratings[i] > ratings[i+1]:
            candies[i] = max(candies[i], candies[i+1] + 1)
    return sum(candies)

def lemonadeChange(bills):
    five = ten = 0
    for b in bills:
        if b == 5:
            five += 1
        elif b == 10:
            if not five: return False
            five -= 1; ten += 1
        else:                           # bill == 20
            if ten and five:
                ten -= 1; five -= 1     # prefer 10+5
            elif five >= 3:
                five -= 3
            else:
                return False
    return True

def eliminateMaximum(dist, speed):
    # turn[i] = turns until monster i arrives
    turns = sorted((d - 1) // s for d, s in zip(dist, speed))
    for i, t in enumerate(turns):
        if t < i:       # monster i arrives before we can kill it
            return i
    return len(dist)

def removeKdigits(num, k):
    stack = []
    for d in num:
        while k and stack and stack[-1] > d:
            stack.pop(); k -= 1
        stack.append(d)
    stack = stack[:-k] if k else stack
    return ''.join(stack).lstrip('0') or '0'

def removeDuplicateLetters(s):
    count = {}
    for c in s: count[c] = count.get(c, 0) + 1
    stack = []; seen = set()
    for c in s:
        count[c] -= 1
        if c in seen:
            continue
        while stack and stack[-1] > c and count[stack[-1]] > 0:
            seen.discard(stack.pop())
        stack.append(c); seen.add(c)
    return ''.join(stack)

def maxNumber(nums1, nums2, k):
    def pick_best(nums, m):
        drop = len(nums) - m
        stack = []
        for n in nums:
            while drop and stack and stack[-1] < n:
                stack.pop(); drop -= 1
            stack.append(n)
        return stack[:m]

    def merge(a, b):
        res = []
        while a and b:
            if a >= b: res.append(a[0]); a = a[1:]
            else:      res.append(b[0]); b = b[1:]
        return res + a + b

    best = []
    for i in range(k + 1):
        if 0 <= i <= len(nums1) and 0 <= k - i <= len(nums2):
            cand = merge(pick_best(nums1, i), pick_best(nums2, k - i))
            if cand > best: best = cand
    return best

def monotoneIncreasingDigits(n):
    s = list(str(n))
    mark = len(s)
    for i in range(len(s) - 1, 0, -1):
        if s[i-1] > s[i]:
            mark = i
            s[i-1] = str(int(s[i-1]) - 1)
    for i in range(mark, len(s)):
        s[i] = '9'
    return int(''.join(s))

def minAddToMakeValid(s):
    open_need = close_need = 0
    for c in s:
        if c == '(':
            close_need += 1
        elif close_need > 0:
            close_need -= 1
        else:
            open_need += 1
    return open_need + close_need

def maximumGain(s, x, y):
    def remove_pair(s, pair, score):
        stack = []; total = 0
        for c in s:
            if stack and stack[-1] == pair[0] and c == pair[1]:
                stack.pop(); total += score
            else:
                stack.append(c)
        return ''.join(stack), total

    if x >= y:
        s, s1 = remove_pair(s, 'ab', x)
        s, s2 = remove_pair(s, 'ba', y)
    else:
        s, s1 = remove_pair(s, 'ba', y)
        s, s2 = remove_pair(s, 'ab', x)
    return s1 + s2

def minSwaps(s):
    unmatched = 0   # unmatched "]" count
    for c in s:
        if c == '[':
            unmatched += 1
        elif unmatched > 0:
            unmatched -= 1
    return (unmatched + 1) // 2

def leastInterval(tasks, n):
    from collections import Counter
    freq = Counter(tasks)
    max_freq = max(freq.values())
    max_count = sum(1 for v in freq.values() if v == max_freq)
    return max((max_freq - 1) * (n + 1) + max_count, len(tasks))

def reorganizeString(s):
    import heapq
    from collections import Counter
    heap = [(-v, k) for k, v in Counter(s).items()]
    heapq.heapify(heap)
    res = []
    while len(heap) > 1:
        c1, ch1 = heapq.heappop(heap)
        c2, ch2 = heapq.heappop(heap)
        res += [ch1, ch2]
        if c1 + 1 < 0: heapq.heappush(heap, (c1 + 1, ch1))
        if c2 + 1 < 0: heapq.heappush(heap, (c2 + 1, ch2))
    if heap:
        c, ch = heap[0]
        if -c > 1: return ''
        res.append(ch)
    return ''.join(res)

def isNStraightHand(hand, groupSize):
    from collections import Counter
    if len(hand) % groupSize: return False
    count = Counter(hand)
    for start in sorted(count):
        n = count[start]
        if n > 0:
            for i in range(groupSize):
                if count[start + i] < n: return False
                count[start + i] -= n
    return True

def maxAverageRatio(classes, extraStudents):
    import heapq
    def gain(p, t):
        return (p + 1) / (t + 1) - p / t
    heap = [(-gain(p, t), p, t) for p, t in classes]
    heapq.heapify(heap)
    for _ in range(extraStudents):
        g, p, t = heapq.heappop(heap)
        p += 1; t += 1
        heapq.heappush(heap, (-gain(p, t), p, t))
    return sum(p / t for _, p, t in heap)

def minIncrementForUnique(nums):
    nums.sort()
    moves = 0
    for i in range(1, len(nums)):
        if nums[i] <= nums[i-1]:
            moves += nums[i-1] + 1 - nums[i]
            nums[i] = nums[i-1] + 1
    return moves

def largestNumber(nums):
    from functools import cmp_to_key
    def cmp(a, b):
        return -1 if a + b > b + a else (1 if a + b < b + a else 0)
    strs = sorted(map(str, nums), key=cmp_to_key(cmp))
    return '0' if strs[0] == '0' else ''.join(strs)

def wiggleSort(nums):
    for i in range(len(nums) - 1):
        if (i % 2 == 0) == (nums[i] > nums[i+1]):
            nums[i], nums[i+1] = nums[i+1], nums[i]
    # Invariant: nums[0]<=nums[1]>=nums[2]<=nums[3]...

def maxArea(height):
    l, r = 0, len(height) - 1
    res = 0
    while l < r:
        res = max(res, min(height[l], height[r]) * (r - l))
        if height[l] < height[r]:
            l += 1
        else:
            r -= 1
    return res

def brokenCalc(startValue, target):
    ops = 0
    while target > startValue:
        if target % 2:
            target += 1     # make even so we can halve
        else:
            target //= 2
        ops += 1
    return ops + startValue - target    # remaining difference by +1 ops

def minimumReplacement(nums):
    n = len(nums)
    ops = 0
    for i in range(n - 2, -1, -1):
        if nums[i] <= nums[i + 1]:
            continue
        parts = (nums[i] + nums[i + 1] - 1) // nums[i + 1]
        ops += parts - 1
        nums[i] = nums[i] // parts  # propagate smallest part leftward
    return ops

def maxMatrixSum(matrix):
    total = neg = 0
    min_abs = float('inf')
    for row in matrix:
        for v in row:
            total += abs(v)
            if v < 0: neg += 1
            min_abs = min(min_abs, abs(v))
    if neg % 2 == 0:
        return total
    return total - 2 * min_abs

def maximumSwap(num):
    digits = list(str(num))
    last = {int(d): i for i, d in enumerate(digits)}
    for i, d in enumerate(digits):
        for dig in range(9, int(d), -1):
            if last.get(dig, -1) > i:
                digits[i], digits[last[dig]] = digits[last[dig]], digits[i]
                return int(''.join(digits))
    return num

def minPatches(nums, n):
    miss = 1        # smallest sum we cannot form yet
    patches = i = 0
    while miss <= n:
        if i < len(nums) and nums[i] <= miss:
            miss += nums[i]; i += 1
        else:
            miss += miss    # patch: add 'miss' itself
            patches += 1
    return patches

def makeIntegerBeautiful(n, target):
    def digit_sum(x): return sum(int(d) for d in str(x))
    result = 0
    power = 1
    while digit_sum(n) > target:
        rem = n % (power * 10)
        if rem:
            add = power * 10 - rem
            n += add; result += add
        power *= 10
    return result

def smallestNumber(num, t):
    if t == 1: return str(num) if '0' not in str(num) else '-1'
    factors = []
    for d in range(9, 1, -1):
        while t % d == 0:
            factors.append(d); t //= d
    if t > 1: return '-1'
    factors.sort()
    candidate = int(''.join(map(str, factors)))
    return str(max(num, candidate))

def partitionLabels(s):
    last = {c: i for i, c in enumerate(s)}
    res = []
    start = end = 0
    for i, c in enumerate(s):
        end = max(end, last[c])
        if i == end:
            res.append(end - start + 1)
            start = i + 1
    return res

def optimalPartition(s):
    # Partition into minimum segments with distinct chars each
    # or: minimum cuts such that each part has all distinct chars
    seen = set(); cuts = 1
    for c in s:
        if c in seen:
            seen = set(); cuts += 1
        seen.add(c)
    return cuts

def maxChunksToSorted(arr):
    # arr is permutation of [0..n-1]
    chunks = max_val = 0
    for i, v in enumerate(arr):
        max_val = max(max_val, v)
        if max_val == i:
            chunks += 1
    return chunks

def maxChunksToSortedII(arr):
    # General case: prefix_max[i] <= suffix_min[i+1]
    import itertools
    n = len(arr)
    pre_max = list(itertools.accumulate(arr, max))
    suf_min = [0] * n
    suf_min[-1] = arr[-1]
    for i in range(n-2, -1, -1):
        suf_min[i] = min(arr[i], suf_min[i+1])
    return 1 + sum(pre_max[i] <= suf_min[i+1] for i in range(n-1))

def canThreePartsEqualSum(arr):
    total = sum(arr)
    if total % 3: return False
    target = total // 3
    count = curr = 0
    for v in arr:
        curr += v
        if curr == target:
            count += 1; curr = 0
    return count >= 3

def removeDigit(number, digit):
    # Remove one occurrence of digit to get largest number
    last = -1
    for i, d in enumerate(number):
        if d == digit:
            if i + 1 < len(number) and number[i+1] > d:
                return number[:i] + number[i+1:]
            last = i
    return number[:last] + number[last+1:]

def breakPalindrome(palindrome):
    n = len(palindrome)
    if n == 1: return ''
    s = list(palindrome)
    for i in range(n // 2):
        if s[i] != 'a':
            s[i] = 'a'
            return ''.join(s)
    s[-1] = 'b'     # all 'a's, change last to 'b'
    return ''.join(s)

def appendCharacters(s, t):
    i = j = 0
    while i < len(s) and j < len(t):
        if s[i] == t[j]:
            j += 1
        i += 1
    return len(t) - j   # characters of t not yet matched

def smallestGoodString(n, m, k):
    # Generic: build smallest string of length n with chars 1..m summing to k
    # Greedy from right: place largest possible char that doesn't overshoot
    res = []
    remaining = k
    for i in range(n, 0, -1):
        char_val = min(m, remaining - (i - 1))  # leave at least 1 per remaining
        res.append(char_val)
        remaining -= char_val
    return ''.join(chr(ord('a') + v - 1) for v in reversed(res))

def scheduleCourse(courses):
    import heapq
    courses.sort(key=lambda x: x[1])
    heap = []   # max-heap of durations (negated)
    time = 0
    for dur, deadline in courses:
        heapq.heappush(heap, -dur)
        time += dur
        if time > deadline:
            time += heapq.heappop(heap)     # remove the longest course taken
    return len(heap)

def findMaximumElegance(items, k):
    import heapq
    items.sort(key=lambda x: -x[0])
    heap = []   # profits of duplicate-category items (min-heap)
    total = distinct = 0
    seen = set()
    for profit, cat in items[:k]:
        total += profit
        if cat not in seen:
            seen.add(cat); distinct += 1
        else:
            heapq.heappush(heap, profit)
    best = total + distinct * distinct
    for profit, cat in items[k:]:
        if cat not in seen and heap:
            seen.add(cat); distinct += 1
            total += profit - heapq.heappop(heap)
            best = max(best, total + distinct * distinct)
    return best

def splitArray(nums, k):
    def feasible(mid):
        parts = count = 0
        for n in nums:
            count += n
            if count > mid:
                parts += 1; count = n
        return parts + 1 <= k

    lo, hi = max(nums), sum(nums)
    while lo < hi:
        mid = (lo + hi) // 2
        if feasible(mid): hi = mid
        else: lo = mid + 1
    return lo

