# With transaction fee:
def maxProfitFee(prices, fee):
    hold = -prices[0]
    cash = 0
    for p in prices[1:]:
        hold = max(hold, cash - p)
        cash = max(cash, hold + p - fee)
    return cash

def bagOfTokensScore(tokens, power):
    tokens.sort()
    l, r = 0, len(tokens) - 1
    score = best = 0
    while l <= r:
        if power >= tokens[l]:
            power -= tokens[l]; score += 1; l += 1
            best = max(best, score)
        elif score > 0:
            power += tokens[r]; score -= 1; r -= 1
        else:
            break
    return best

