def minimumReplacement(nums):
    n = len(nums)
    ops = 0
    for i in range(n - 2, -1, -1):
        if nums[i] <= nums[i + 1]:
            continue
        parts = (nums[i] + nums[i + 1] - 1) // nums[i + 1]
        ops += parts - 1
        nums[i] = nums[i] // parts  # smallest part becomes new nums[i]
    return ops

def minSwapsCouples(row):
    # Greedy: for each couple seat, find partner and swap
    pos = {v: i for i, v in enumerate(row)}
    swaps = 0
    for i in range(0, len(row), 2):
        partner = row[i] ^ 1    # XOR: 0<->1, 2<->3, ...
        if row[i + 1] != partner:
            j = pos[partner]
            row[i + 1], row[j] = row[j], row[i + 1]
            pos[row[j]] = j
            swaps += 1
    return swaps

def minimizeXor(num, target):
    tc = bin(target).count('1')
    nc = bin(num).count('1')
    res = num
    # Remove extra bits from least significant positions
    for i in range(32):
        if nc <= tc: break
        if res & (1 << i):
            res ^= (1 << i); nc -= 1
    # Add bits at least significant free positions
    for i in range(32):
        if nc >= tc: break
        if not res & (1 << i):
            res |= (1 << i); nc += 1
    return res

def minimumSum(nums):
    # Greedy: minimize sum by using bit manipulation
    # Split into two numbers, each taking alternating bits
    bits = []
    for n in nums:
        for i in range(30):
            if n & (1 << i): bits.append(1 << i)
    bits.sort(reverse=True)
    a = b = 0
    for i, bit in enumerate(bits):
        if i % 2 == 0: a |= bit
        else: b |= bit
    return a + b

def maximumImportance(n, roads):
