    for u, v in roads:
        degree[u] += 1; degree[v] += 1
    degree.sort(reverse=True)
    # Assign value n to highest degree, n-1 to next, etc.
    return sum(degree[i] * (n - i) for i in range(n))

def reconstructMatrix(upper, lower, colsum):
    n = len(colsum)
    res = [[0]*n, [0]*n]
    for j in range(n):
        if colsum[j] == 2:
            res[0][j] = res[1][j] = 1
            upper -= 1; lower -= 1
        elif colsum[j] == 1:
            if upper >= lower:
                res[0][j] = 1; upper -= 1
            else:
                res[1][j] = 1; lower -= 1
    return res if upper == 0 and lower == 0 else []

def minimumCost(m, n, horizontalCut, verticalCut):
    horizontalCut.sort(reverse=True)
    verticalCut.sort(reverse=True)
    h_pieces = v_pieces = 1
    res = i = j = 0
    while i < len(horizontalCut) or j < len(verticalCut):
        h = horizontalCut[i] if i < len(horizontalCut) else -1
        v = verticalCut[j] if j < len(verticalCut) else -1
        if h >= v:
            res += h * v_pieces; h_pieces += 1; i += 1
        else:
            res += v * h_pieces; v_pieces += 1; j += 1
    return res

def strongPasswordChecker(password):
    n = len(password)
    missing = 3 - any(c.islower() for c in password)                 - any(c.isupper() for c in password)                 - any(c.isdigit() for c in password)
    # Count repeating sequences
    replace = one = two = 0
    i = 2
    while i < n:
        if password[i] == password[i-1] == password[i-2]:
            length = 2
            while i < n and password[i] == password[i-1]:
                length += 1; i += 1
            replace += length // 3
            if length % 3 == 0: one += 1
            elif length % 3 == 1: two += 1
        else:
            i += 1
    if n < 6:   return max(6 - n, missing)
    if n <= 20: return max(replace, missing)
    # Need deletions
    delete = n - 20
    replace -= min(delete, one)
    replace -= min(max(delete - one, 0), two * 2) // 2
    replace -= max(delete - one - 2 * two, 0) // 3
    return delete + max(replace, missing)

def predictPartyVictory(senate):
    from collections import deque
    r = deque(); d = deque()
    for i, c in enumerate(senate):
        (r if c == 'R' else d).append(i)
    n = len(senate)
    while r and d:
        ri, di = r.popleft(), d.popleft()
        if ri < di: r.append(ri + n)
        else:        d.append(di + n)
    return 'Radiant' if r else 'Dire'

def minAbsoluteSumDiff(nums1, nums2):
    MOD = 10**9 + 7
    from bisect import bisect_left
    sorted1 = sorted(nums1)
    base = total = sum(abs(a - b) for a, b in zip(nums1, nums2))
    best_save = 0
    for a, b in zip(nums1, nums2):
        diff = abs(a - b)
        i = bisect_left(sorted1, b)
        for j in [i, i - 1]:
            if 0 <= j < len(sorted1):
                best_save = max(best_save, diff - abs(sorted1[j] - b))
    return (total - best_save) % MOD

