def minimumOperations(nums):
    # Make array non-decreasing via minimum removals
    from bisect import bisect_left
    # LIS-based: answer = n - LIS_length
    lis = []
    for n in nums:
        i = bisect_left(lis, n)
        if i == len(lis): lis.append(n)
        else: lis[i] = n
    return len(nums) - len(lis)

def stoneGameVII(stones):
    # Alice/Bob take from ends; greedy DP or interval game
    n = len(stones)
    prefix = [0] * (n + 1)
    for i, s in enumerate(stones): prefix[i+1] = prefix[i] + s

    from functools import lru_cache
    @lru_cache(None)
    def dp(l, r):
        if l > r: return 0
        total = prefix[r+1] - prefix[l]
        # Remove left: get total-stones[l], opponent plays dp(l+1, r)
        # Remove right: get total-stones[r], opponent plays dp(l, r-1)
        return max(total - stones[l] - dp(l+1, r),
                   total - stones[r] - dp(l, r-1))
    return dp(0, n-1)

def scheduleTasks(tasks, sessions):
    # Sort by (remaining_time, end_time); fit as many as possible
    tasks.sort(key=lambda t: (t[1], t[0]))  # sort by deadline, then duration
    heap = []
    import heapq
    time = 0
    for dur, deadline in tasks:
        heapq.heappush(heap, (deadline, dur))
        if time + dur <= deadline:
            time += dur
        else:
            # Skip the task with latest deadline if it doesn't fit
            heapq.heappop(heap)
    return len(heap)

def minMovesToMakePalindrome(s):
    s = list(s)
    l, r = 0, len(s) - 1
    moves = 0
    while l < r:
        if s[l] == s[r]:
            l += 1; r -= 1
        else:
            # Find match for s[l] on right side or s[r] on left side
            i = r
            while i > l and s[i] != s[l]: i -= 1
            if i == l:  # s[l] is unique, move it to middle
                s[l], s[l+1] = s[l+1], s[l]; moves += 1
            else:
                while i < r:
                    s[i], s[i+1] = s[i+1], s[i]; i += 1; moves += 1
                l += 1; r -= 1
    return moves

