def rotate(nums, k):
    n = len(nums); k %= n
    def rev(l, r):
        while l < r: nums[l], nums[r] = nums[r], nums[l]; l += 1; r -= 1
    rev(0, n-1); rev(0, k-1); rev(k, n-1)

def longestPalindrome(s):
    def expand(l, r):
        while l >= 0 and r < len(s) and s[l] == s[r]: l -= 1; r += 1
        return s[l+1:r]
    res = ''
    for i in range(len(s)):
        for p in [expand(i,i), expand(i,i+1)]:
            if len(p) > len(res): res = p
    return res

def findMaxAverage(nums, k):
    window = sum(nums[:k]); best = window
    for i in range(k, len(nums)):
        window += nums[i] - nums[i-k]
        best = max(best, window)
    return best / k

def maxSlidingWindow(nums, k):
    from collections import deque
    dq = deque(); res = []
    for i, n in enumerate(nums):
        while dq and nums[dq[-1]] < n: dq.pop()
        dq.append(i)
        if dq[0] < i-k+1: dq.popleft()
        if i >= k-1: res.append(nums[dq[0]])
    return res

def minKBitFlips(nums, k):
    flips = count = 0; flip_queue = []
    for i, n in enumerate(nums):
        if flip_queue and i >= flip_queue[0] + k:
            flips -= 1; flip_queue.pop(0)
        if (n + flips) % 2 == 0:   # current bit is 0 after flips
            if i + k > len(nums): return -1
            flips += 1; count += 1; flip_queue.append(i)
    return count

def numberOfSubarrays(nums, k):
    # Fixed window: count subarrays of size exactly k with k odd numbers
    # = atMost(k) - atMost(k-1)
    def atMost(goal):
        count = left = curr = 0
        for right, n in enumerate(nums):
            curr += n % 2
            while curr > goal: curr -= nums[left] % 2; left += 1
            count += right - left + 1
        return count
    return atMost(k) - atMost(k-1)

