def characterReplacement(s, k):
    count = {}; left = max_freq = res = 0
    for right, c in enumerate(s):
        count[c] = count.get(c, 0) + 1
        max_freq = max(max_freq, count[c])
        if right - left + 1 - max_freq > k:
            count[s[left]] -= 1; left += 1
        res = max(res, right - left + 1)
    return res

def longestSubarray(nums, limit):
    from collections import deque
    inc = deque(); dec = deque(); left = res = 0
    for right, n in enumerate(nums):
        while inc and nums[inc[-1]] > n: inc.pop()
        while dec and nums[dec[-1]] < n: dec.pop()
        inc.append(right); dec.append(right)
        while dec[0] != inc[0] and nums[dec[0]] - nums[inc[0]] > limit:
            left += 1
            if inc[0] < left: inc.popleft()
            if dec[0] < left: dec.popleft()
        res = max(res, right - left + 1)
    return res

def minSubArrayLen(target, nums):
    left = curr = 0; res = float('inf')
    for right, n in enumerate(nums):
        curr += n
        while curr >= target:
            res = min(res, right - left + 1)
            curr -= nums[left]; left += 1
    return res if res != float('inf') else 0

def subarraysWithKDistinct(nums, k):
    def atMost(k):
        from collections import defaultdict
        count = defaultdict(int); left = res = 0
        for right, n in enumerate(nums):
            count[n] += 1
            while len(count) > k:
                count[nums[left]] -= 1
                if count[nums[left]] == 0: del count[nums[left]]
                left += 1
            res += right - left + 1
        return res
    return atMost(k) - atMost(k-1)

def numSubarrayBoundedMax(nums, left, right):
    # Count subarrays with max in [left, right]
    # = countAtMost(right) - countAtMost(left-1)
    def countAtMost(bound):
        count = cur = 0
        for n in nums:
            cur = cur + 1 if n <= bound else 0
            count += cur
        return count
    return countAtMost(right) - countAtMost(left-1)

def findMaxLength(nums):
    # Longest subarray with equal 0s and 1s
    balance = 0; first = {0: -1}; res = 0
    for i, n in enumerate(nums):
        balance += 1 if n else -1
        if balance in first:
            res = max(res, i - first[balance])
        else:
            first[balance] = i
    return res

