def matrixBlockSum(mat, k):
    m, n = len(mat), len(mat[0])
    p = [[0]*(n+1) for _ in range(m+1)]
    for r in range(m):
        for c in range(n):
            p[r+1][c+1] = mat[r][c]+p[r][c+1]+p[r+1][c]-p[r][c]
