        for c in range(n):
            r1,c1 = max(0,r-k), max(0,c-k)
            r2,c2 = min(m-1,r+k), min(n-1,c+k)
            res[r][c] = p[r2+1][c2+1]-p[r1][c2+1]-p[r2+1][c1]+p[r1][c1]
