def addBoldTag(s, words):
    n = len(s); bold = [0]*(n+1)
    for w in words:
        start = 0
        while True:
            pos = s.find(w, start)
            if pos == -1: break
            bold[pos] += 1; bold[pos+len(w)] -= 1
            start = pos + 1
    # Build result
    res = []; active = 0; open_tag = False
    for i in range(n):
        active += bold[i]
        if active > 0 and not open_tag: res.append('<b>'); open_tag = True
        if active == 0 and open_tag:    res.append('</b>'); open_tag = False
        res.append(s[i])
    if open_tag: res.append('</b>')
    return ''.join(res)

