def isSubseqMulti(s, t, queries):
    from bisect import bisect_left
    pos = {}
    for i, c in enumerate(t):
        pos.setdefault(c, []).append(i)
    def check(q):
        cur = 0
        for c in q:
            if c not in pos: return False
            idx = bisect_left(pos[c], cur)
            if idx == len(pos[c]): return False
            cur = pos[c][idx] + 1
        return True
    return [check(q) for q in queries]

def compress(chars):
    write = read = 0
    while read < len(chars):
        char = chars[read]; count = 0
        while read < len(chars) and chars[read] == char:
            read += 1; count += 1
        chars[write] = char; write += 1
        if count > 1:
