    return write

def backspaceCompare(s, t):
    def process(s):
        stack = []
        for c in s:
            if c != '#': stack.append(c)
            elif stack:  stack.pop()
        return stack
    return process(s) == process(t)

# O(1) space: two pointers from end
def backspaceCompareO1(s, t):
    def next_char(s, i):
        skip = 0
        while i >= 0:
            if s[i] == '#': skip += 1; i -= 1
            elif skip:       skip -= 1; i -= 1
            else:            break
        return i
    i, j = len(s)-1, len(t)-1
    while i >= 0 or j >= 0:
        i = next_char(s, i); j = next_char(t, j)
        if i >= 0 and j >= 0 and s[i] != t[j]: return False
        if (i >= 0) != (j >= 0): return False
        i -= 1; j -= 1
    return True

def splitArray(nums, k):
    def feasible(mid):
        parts = curr = 0
        for n in nums:
            curr += n
            if curr > mid: parts += 1; curr = n
        return parts + 1 <= k
    lo, hi = max(nums), sum(nums)
    while lo < hi:
        mid = (lo+hi)//2
        if feasible(mid): hi = mid
        else:             lo = mid+1
    return lo

def findUnsortedSubarray(nums):
    n = len(nums); lo = hi = -1; max_seen = min_seen = float('inf')
    for i in range(n-1,-1,-1):
        min_seen = min(min_seen, nums[i])
        if nums[i] > min_seen: lo = i
    max_seen = float('-inf')
    for i in range(n):
        max_seen = max(max_seen, nums[i])
        if nums[i] < max_seen: hi = i
    return 0 if hi == -1 else hi - lo + 1

def maxWidthRamp(nums):
    n = len(nums); stack = []
    for i in range(n):
        if not stack or nums[stack[-1]] > nums[i]:
            stack.append(i)
    res = 0
    for j in range(n-1,-1,-1):
        while stack and nums[stack[-1]] <= nums[j]:
            res = max(res, j - stack.pop())
    return res

