def boundaryOfBinaryTree(root):
    if not root: return []
    def is_leaf(n): return not n.left and not n.right
    def left_boundary(n):
        res = []
        while n:
            if not is_leaf(n): res.append(n.val)
            n = n.left if n.left else n.right
        return res
    def right_boundary(n):
        res = []
        while n:
            if not is_leaf(n): res.append(n.val)
            n = n.right if n.right else n.left
        return res[::-1]
    def leaves(n):
        if not n: return []
        if is_leaf(n): return [n.val]
        return leaves(n.left) + leaves(n.right)
    return ([root.val] + left_boundary(root.left)
            + leaves(root.left) + leaves(root.right)
            + right_boundary(root.right))

def morrisInorder(root):
    res = []; cur = root
    while cur:
        if not cur.left:
            res.append(cur.val); cur = cur.right
        else:
            # Find inorder predecessor
            prev = cur.left
            while prev.right and prev.right is not cur:
                prev = prev.right
            if not prev.right:
                prev.right = cur    # create thread
                cur = cur.left
            else:
                prev.right = None   # remove thread
                res.append(cur.val)
                cur = cur.right
    return res

