def minDepthBFS(root):
    from collections import deque
    if not root: return 0
    q = deque([(root, 1)])
    while q:
        node, d = q.popleft()
        if not node.left and not node.right: return d
        if node.left:  q.append((node.left,  d+1))
        if node.right: q.append((node.right, d+1))

def isBalanced(root):
    def height(node):
        if not node: return 0
        lh = height(node.left)
        if lh == -1: return -1
        rh = height(node.right)
        if rh == -1: return -1
        if abs(lh - rh) > 1: return -1
        return 1 + max(lh, rh)
    return height(root) != -1

def diameterOfBinaryTree(root):
    best = [0]
    def depth(node):
        if not node: return 0
        l = depth(node.left)
        r = depth(node.right)
        best[0] = max(best[0], l + r)
        return 1 + max(l, r)
    depth(root); return best[0]

def widthOfBinaryTree(root):
    from collections import deque
    if not root: return 0
    res = 0; q = deque([(root, 0)])
    while q:
        n = len(q)
        _, first = q[0]
        for _ in range(n):
            node, idx = q.popleft()
            if node.left:  q.append((node.left,  2*idx))
            if node.right: q.append((node.right, 2*idx+1))
        res = max(res, idx - first + 1)
    return res

def isSameTree(p, q):
