    def find_mid(l, r):
        slow = fast = l
        while fast is not r and fast.next is not r:
            slow = slow.next; fast = fast.next.next
        return slow
    def build(l, r):
        if l is r: return None
        mid = find_mid(l, r)
        node = TreeNode(mid.val)
        node.left  = build(l, mid)
        node.right = build(mid.next, r)
        return node
    return build(head, None)

def bstFromPreorder(preorder):
    root = TreeNode(preorder[0])
    stack = [root]
    for val in preorder[1:]:
        node = TreeNode(val)
        if val < stack[-1].val:
            stack[-1].left = node
        else:
            parent = stack[-1]
            while stack and stack[-1].val < val:
                parent = stack.pop()
            parent.right = node
        stack.append(node)
    return root

