            if not node: return ['#']
            return [str(node.val)] + dfs(node.left) + dfs(node.right)
        return ','.join(dfs(root))

    def deserialize(self, data):
        from collections import deque
        vals = deque(data.split(','))
        def dfs():
            v = vals.popleft()
            if v == '#': return None
            node = TreeNode(int(v))
            node.left  = dfs()
            node.right = dfs()
            return node
        return dfs()

