def lowestCommonAncestor(root, p, q):
    if not root or root is p or root is q: return root
    left  = lowestCommonAncestor(root.left,  p, q)
    right = lowestCommonAncestor(root.right, p, q)
    return root if left and right else (left or right)

def lowestCommonAncestorBST(root, p, q):
    while root:
        if p.val < root.val and q.val < root.val:
            root = root.left
        elif p.val > root.val and q.val > root.val:
            root = root.right
        else:
            return root

def searchBST(root, val):
    while root:
        if val == root.val: return root
        root = root.left if val < root.val else root.right
    return None

def insertIntoBST(root, val):
    if not root: return TreeNode(val)
    if val < root.val: root.left  = insertIntoBST(root.left,  val)
    else:              root.right = insertIntoBST(root.right, val)
    return root

def trimBST(root, low, high):
    if not root: return None
    if root.val < low:  return trimBST(root.right, low, high)
    if root.val > high: return trimBST(root.left,  low, high)
    root.left  = trimBST(root.left,  low, high)
    root.right = trimBST(root.right, low, high)
    return root

def closestValue(root, target):
    closest = root.val
    while root:
        if abs(root.val - target) < abs(closest - target):
            closest = root.val
        root = root.left if target < root.val else root.right
    return closest

def closestKValues(root, target, k):
    # Inorder traversal + sliding window of size k
    import heapq; heap = []
    def inorder(node):
        if not node: return
        inorder(node.left)
        heapq.heappush(heap, (-abs(node.val - target), node.val))
        if len(heap) > k: heapq.heappop(heap)
        inorder(node.right)
    inorder(root)
    return [v for _, v in heap]

class BSTIterator:
    def __init__(self, root):
        self.stack = []
        self._push_left(root)

    def _push_left(self, node):
        while node: self.stack.append(node); node = node.left

    def next(self):
        node = self.stack.pop()
        self._push_left(node.right)
        return node.val

    def hasNext(self):
        return bool(self.stack)

def minDiffInBST(root):
    prev = [None]; best = [float('inf')]
