        if not node: return
        inorder(node.left)
        if prev[0] is not None:
            best[0] = min(best[0], node.val - prev[0])
        prev[0] = node.val
        inorder(node.right)
    inorder(root); return best[0]

def findMode(root):
    # Track consecutive equal values in inorder
    prev = [None]; cur_cnt = [0]; max_cnt = [0]; modes = []
    def inorder(node):
        if not node: return
        inorder(node.left)
        cur_cnt[0] = cur_cnt[0]+1 if node.val==prev[0] else 1
        prev[0] = node.val
        if cur_cnt[0] > max_cnt[0]: max_cnt[0]=cur_cnt[0]; modes.clear()
        if cur_cnt[0] == max_cnt[0]: modes.append(node.val)
        inorder(node.right)
    inorder(root); return modes

def findTarget(root, k):
    vals = []
    def inorder(node):
        if not node: return
        inorder(node.left); vals.append(node.val); inorder(node.right)
    inorder(root)
    l, r = 0, len(vals) - 1
    while l < r:
        s = vals[l] + vals[r]
        if s == k:   return True
        if s < k:    l += 1
        else:        r -= 1
    return False

def rangeSumBST(root, low, high):
    if not root: return 0
    s = root.val if low <= root.val <= high else 0
    if root.val > low:  s += rangeSumBST(root.left,  low, high)
    if root.val < high: s += rangeSumBST(root.right, low, high)
    return s

def delNodes(root, to_delete):
    to_del = set(to_delete); forest = []
    def dfs(node, is_root):
        if not node: return None
        deleted = node.val in to_del
        if is_root and not deleted: forest.append(node)
        node.left  = dfs(node.left,  deleted)
        node.right = dfs(node.right, deleted)
        return None if deleted else node
    dfs(root, True); return forest

def addOneRow(root, val, depth):
    if depth == 1:
        new = TreeNode(val); new.left = root; return new
    from collections import deque
    q = deque([root]); level = 1
    while level < depth - 1:
        for _ in range(len(q)):
            node = q.popleft()
            if node.left:  q.append(node.left)
            if node.right: q.append(node.right)
        level += 1
    for node in q:
        new_l = TreeNode(val); new_r = TreeNode(val)
        new_l.left  = node.left;  node.left  = new_l
        new_r.right = node.right; node.right = new_r
    return root

def componentValue(root, nums):
    # Count of cuts = (num_valid_subtrees - 1); try each candidate sum
    n = sum(nums); totals = []
    def sub_sum(node):
        if not node: return 0
        s = node.val + sub_sum(node.left) + sub_sum(node.right)
        totals.append(s); return s
    sub_sum(root)
    for k in range(1, n + 1):
        if n % k == 0:
            target = n // k
            if totals.count(target) * target == n:
                return k - 1
    return 0

