def rob(root):
    def dfs(node):
        # returns (rob_this, skip_this)
        if not node: return 0, 0
        ll, ls = dfs(node.left)
        rl, rs = dfs(node.right)
        rob_cur  = ls + rs + node.val   # must skip children
        skip_cur = max(ll, ls) + max(rl, rs)
        return rob_cur, skip_cur
    return max(dfs(root))

def minCameraCover(root):
