        if not node: return 2
        l = dfs(node.left); r = dfs(node.right)
        if l == 0 or r == 0:
            cameras[0] += 1; return 1
        if l == 1 or r == 1:
            return 2
        return 0    # both covered but no camera pointing at current
    if dfs(root) == 0: cameras[0] += 1
    return cameras[0]

def collectTheCoins(coins, edges):
    from collections import defaultdict, deque
    n = len(coins); adj = defaultdict(set)
    for u, v in edges:
        adj[u].add(v); adj[v].add(u)
    # Remove all leaf nodes with coin=0 twice (two rounds of pruning)
    deg = [len(adj[i]) for i in range(n)]
    q = deque(i for i in range(n) if deg[i]==1 and coins[i]==0)
    while q:
        leaf = q.popleft()
        for nb in adj[leaf]:
            adj[nb].discard(leaf); deg[nb] -= 1
            if deg[nb]==1 and coins[nb]==0: q.append(nb)
        adj[leaf].clear()
    # Remove two more layers of leaves (2 edges distance)
    for _ in range(2):
        q = deque(i for i in range(n) if len(adj[i])==1)
        while q:
            leaf = q.popleft()
            for nb in list(adj[leaf]):
                adj[nb].discard(leaf)
            adj[leaf].clear()
    return max(0, sum(len(v)>0 for v in adj.values()) - 1) * 2

def minTime(n, edges, hasApple):
    from collections import defaultdict
    adj = defaultdict(list)
    for u, v in edges:
        adj[u].append(v); adj[v].append(u)
    def dfs(node, parent):
        time = 0
        for child in adj[node]:
            if child == parent: continue
            child_time = dfs(child, node)
            if child_time > 0 or hasApple[child]:
                time += child_time + 2
        return time
    return dfs(0, -1)

def sumOfDistancesInTree(n, edges):
    from collections import defaultdict
    adj = defaultdict(list)
    for u, v in edges: adj[u].append(v); adj[v].append(u)
    cnt = [1] * n    # subtree sizes
    ans = [0] * n    # answer for each node

    def dfs1(node, parent):
        for child in adj[node]:
            if child != parent:
                dfs1(child, node)
                cnt[node] += cnt[child]
                ans[node] += ans[child] + cnt[child]

    def dfs2(node, parent):
        for child in adj[node]:
            if child != parent:
                # reroot: move root from node to child
                ans[child] = ans[node] - cnt[child] + (n - cnt[child])
                dfs2(child, node)

    dfs1(0, -1); dfs2(0, -1)
    return ans

def countSubTrees(n, edges, labels):
    from collections import defaultdict
    adj = defaultdict(list)
    for u, v in edges: adj[u].append(v); adj[v].append(u)
    ans = [0] * n

    def dfs(node, parent):
        count = defaultdict(int)
        count[labels[node]] = 1
        for child in adj[node]:
            if child != parent:
                child_count = dfs(child, node)
                for k, v in child_count.items():
                    count[k] += v
        ans[node] = count[labels[node]]
        return count

    dfs(0, -1); return ans

def distanceK(root, target, k):
    from collections import defaultdict, deque
    # Add parent pointers to convert to undirected graph
    parent = {root: None}
    def dfs(node, par):
        if not node: return
        if node.left:  parent[node.left]  = node; dfs(node.left,  node)
        if node.right: parent[node.right] = node; dfs(node.right, node)
    dfs(root, None)

    q = deque([(target, 0)]); visited = {target}
    res = []
    while q:
        node, dist = q.popleft()
        if dist == k: res.append(node.val); continue
        for nb in [node.left, node.right, parent[node]]:
            if nb and nb not in visited:
                visited.add(nb); q.append((nb, dist+1))
    return res

def amountOfTime(root, start):
    from collections import defaultdict, deque
    adj = defaultdict(list)
    def build(node, parent):
        if not node: return
        if parent: adj[node.val].append(parent.val); adj[parent.val].append(node.val)
        build(node.left, node); build(node.right, node)
    build(root, None)

    visited = {start}; q = deque([start]); time = -1
