def countPairs(root, distance):
    count = [0]
    def dfs(node):
        if not node: return []
        if not node.left and not node.right: return [1]   # leaf at depth 1
        left_dists  = dfs(node.left)
        right_dists = dfs(node.right)
        for l in left_dists:
            for r in right_dists:
                if l + r <= distance: count[0] += 1
        return [d + 1 for d in left_dists + right_dists]
    dfs(root); return count[0]

class TreeAncestor:
    def __init__(self, n, parent):
        LOG = 16
        self.up = [[-1]*LOG for _ in range(n)]
        for i, p in enumerate(parent):
            self.up[i][0] = p
        for j in range(1, LOG):
            for i in range(n):
                if self.up[i][j-1] != -1:
                    self.up[i][j] = self.up[self.up[i][j-1]][j-1]

    def getKthAncestor(self, node, k):
        for j in range(16):
            if (k >> j) & 1:
                node = self.up[node][j]
                if node == -1: return -1
        return node

def build_lca(n, edges, root=0):
    from collections import defaultdict
    LOG = 16
    adj = defaultdict(list)
    for u, v, *w in edges: adj[u].append((v, w[0] if w else 1)); adj[v].append((u, w[0] if w else 1))
    depth = [0]*n; up = [[-1]*LOG for _ in range(n)]; dist = [0]*n

    def dfs(u, p, d, wt):
        depth[u] = d; up[u][0] = p; dist[u] = wt
        for j in range(1, LOG):
            if up[u][j-1]!=-1: up[u][j]=up[up[u][j-1]][j-1]
        for v, w in adj[u]:
            if v!=p: dfs(v, u, d+1, wt^w)
    dfs(root, root, 0, 0)

    def lca(u, v):
        if depth[u] < depth[v]: u, v = v, u
        diff = depth[u]-depth[v]
        for j in range(LOG):
            if (diff>>j)&1: u=up[u][j]
        if u==v: return u
        for j in range(LOG-1,-1,-1):
            if up[u][j]!=up[v][j]: u=up[u][j]; v=up[v][j]
        return up[u][0]

    return lca, dist, depth

def numberOfGoodPaths(vals, edges):
    from collections import defaultdict
    n = len(vals)
    adj = defaultdict(list)
    for u, v in edges: adj[u].append(v); adj[v].append(u)

    parent = list(range(n)); max_val = vals[:]

    def find(x):
        while parent[x] != x: parent[x] = parent[parent[x]]; x = parent[x]
        return x

    def union(a, b):
        a, b = find(a), find(b)
        if a == b: return
        if max_val[a] < max_val[b]: a, b = b, a
        parent[b] = a; max_val[a] = max(max_val[a], max_val[b])

    # Group nodes by value; process ascending
    from collections import Counter
    nodes_by_val = defaultdict(list)
    for i, v in enumerate(vals): nodes_by_val[v].append(i)

    ans = n   # each node alone is a path
    for v in sorted(nodes_by_val):
        for u in nodes_by_val[v]:
            for nb in adj[u]:
                if vals[nb] <= v: union(u, nb)
