    def build(r, c, size):
        if size == 1: return Node(grid[r][c]==1, True)
        half = size // 2
        tl = build(r,        c,        half)
        tr = build(r,        c+half,   half)
        bl = build(r+half,   c,        half)
        br = build(r+half,   c+half,   half)
        if all(ch.isLeaf and ch.val==tl.val for ch in [tl,tr,bl,br]):
            return Node(tl.val, True)
