def catWinsMouse(grid):
    # Game theory on tree/graph: use memoized BFS/DFS with state (cat, mouse, turn)
    from functools import lru_cache
    rows, cols = len(grid), len(grid[0])
    # Find positions
    cat = mouse = food = None
    for r in range(rows):
        for c in range(cols):
            if grid[r][c]=='C': cat=(r,c)
            elif grid[r][c]=='M': mouse=(r,c)
            elif grid[r][c]=='F': food=(r,c)

    @lru_cache(None)
    def dp(cr, cc, mr, mc, turn, moves):
        if moves >= rows*cols*2: return False  # too many moves = draw
        if (cr,cc)==(mr,mc): return False      # cat catches mouse
        if (mr,mc)==food: return True          # mouse reaches food
        if (cr,cc)==food: return False         # cat at food blocks

        dirs = [(0,1),(0,-1),(1,0),(-1,0)]
        if turn == 0:  # mouse's turn
            for dr,dc in dirs+([(0,0)],):
                nr,nc = mr+dr, mc+dc
                if 0<=nr<rows and 0<=nc<cols and grid[nr][nc]!='#':
                    if dp(cr,cc,nr,nc,1,moves+1): return True
            return False
        else:          # cat's turn
            for dr,dc in dirs:
                nr,nc = cr+dr, cc+dc
                if 0<=nr<rows and 0<=nc<cols and grid[nr][nc]!='#':
                    if not dp(nr,nc,mr,mc,0,moves+1): return False
            return True

    return dp(cat[0],cat[1],mouse[0],mouse[1],1,0)

def xorDistanceQueries(n, edges, queries):
    # Build adjacency, DFS for XOR-prefix from root, LCA for path queries
    from collections import defaultdict
    adj = defaultdict(list)
    for u,v,w in edges: adj[u].append((v,w)); adj[v].append((u,w))
    LOG=16; depth=[0]*n; up=[[-1]*LOG for _ in range(n)]; xor_root=[0]*n

    def dfs(u, p, d, x):
        depth[u]=d; up[u][0]=p; xor_root[u]=x
        for j in range(1,LOG):
            if up[u][j-1]!=-1: up[u][j]=up[up[u][j-1]][j-1]
        for v,w in adj[u]:
            if v!=p: dfs(v,u,d+1,x^w)
    dfs(0,0,0,0)

    def lca(u,v):
        if depth[u]<depth[v]: u,v=v,u
        diff=depth[u]-depth[v]
        for j in range(LOG):
            if (diff>>j)&1: u=up[u][j]
        if u==v: return u
        for j in range(LOG-1,-1,-1):
            if up[u][j]!=up[v][j]: u=up[u][j]; v=up[v][j]
        return up[u][0]

    return [xor_root[u]^xor_root[v] for u,v in queries]

