                rows[r].add(d); cols[c].add(d)
                boxes[(r//3)*3+c//3].add(d)
            else:
                empty.append((r, c))

    def bt(idx):
        if idx == len(empty): return True
        r, c = empty[idx]; b = (r//3)*3+c//3
        for d in '123456789':
            if d not in rows[r] and d not in cols[c] and d not in boxes[b]:
                board[r][c] = d
                rows[r].add(d); cols[c].add(d); boxes[b].add(d)
                if bt(idx + 1): return True
                board[r][c] = '.'
                rows[r].discard(d); cols[c].discard(d); boxes[b].discard(d)
        return False

    bt(0)

def exist(board, word):
    m, n = len(board), len(board[0])

    def bt(r, c, idx):
        if idx == len(word): return True
        if r < 0 or r >= m or c < 0 or c >= n: return False
        if board[r][c] != word[idx]: return False
        tmp, board[r][c] = board[r][c], '#'     # mark visited
        found = any(bt(r+dr, c+dc, idx+1)
                    for dr, dc in [(0,1),(0,-1),(1,0),(-1,0)])
        board[r][c] = tmp                       # restore
        return found

    return any(bt(r, c, 0) for r in range(m) for c in range(n))

def tilingRectangle(n, m, t):
    count = [float('inf')]
    grid = [[False]*m for _ in range(n)]

    def find_empty():
        for r in range(n):
            for c in range(m):
                if not grid[r][c]: return r, c
        return None

    def bt(placed):
        if placed >= count[0]: return
        cell = find_empty()
        if not cell:
            count[0] = placed; return
        r, c = cell
        sz = 1
        while (r+sz <= n and c+sz <= m and
               all(not grid[r+i][c+j] for i in range(sz) for j in range(sz))):
            sz += 1
        for s in range(sz-1, 0, -1):
            for i in range(s):
                for j in range(s): grid[r+i][c+j] = True
            bt(placed + 1)
            for i in range(s):
                for j in range(s): grid[r+i][c+j] = False

    bt(0)
    return count[0]

def partition(s):
    n = len(s)
    # Precompute palindrome table
    is_pal = [[False]*n for _ in range(n)]
    for i in range(n-1, -1, -1):
        for j in range(i, n):
            is_pal[i][j] = (s[i]==s[j]) and (j-i<=2 or is_pal[i+1][j-1])

    res = []
    def bt(start, path):
        if start == n:
            res.append(path[:]); return
        for end in range(start, n):
            if is_pal[start][end]:
                path.append(s[start:end+1])
                bt(end + 1, path)
                path.pop()
    bt(0, [])
    return res

def restoreIpAddresses(s):
    res = []
    def bt(start, parts):
        if len(parts) == 4:
            if start == len(s): res.append('.'.join(parts))
            return
        remaining_parts = 4 - len(parts)
        remaining_chars = len(s) - start
        if not (remaining_parts <= remaining_chars <= 3 * remaining_parts):
            return                  # length prune
        for length in range(1, 4):
            if start + length > len(s): break
            seg = s[start:start+length]
            if len(seg) > 1 and seg[0] == '0': break
            if int(seg) > 255: break
            bt(start + length, parts + [seg])
    bt(0, [])
    return res

def maxUniqueSplit(s):
    seen = set(); res = [0]
    def bt(start, count):
        if count + (len(s) - start) <= res[0]: return   # can't beat best
        if start == len(s):
            res[0] = max(res[0], count); return
        for end in range(start+1, len(s)+1):
            sub = s[start:end]
            if sub not in seen:
                seen.add(sub)
                bt(end, count + 1)
                seen.discard(sub)
    bt(0, 0)
    return res[0]

