        if start in memo: return memo[start]
        if start == len(s): return ['']
        res = []
        for end in range(start+1, len(s)+1):
            word = s[start:end]
            if word in word_set:
                for rest in bt(end):
                    res.append(word + (' ' if rest else '') + rest)
        memo[start] = res
        return res

    return bt(0)

