def addOperators(num, target):
    res = []
    def bt(idx, path, value, prev):
        if idx == len(num):
            if value == target: res.append(path)
            return
        for end in range(idx+1, len(num)+1):
            s = num[idx:end]
            if len(s) > 1 and s[0] == '0': break   # no leading zeros
            n = int(s)
            if idx == 0:
                bt(end, s, n, n)
            else:
                bt(end, path+'+'+s, value+n, n)
                bt(end, path+'-'+s, value-n, -n)
                # multiply: undo prev add/sub, apply mult
                bt(end, path+'*'+s, value - prev + prev*n, prev*n)
    bt(0, '', 0, 0)
    return res

def diffWaysToCompute(expression):
    memo = {}
    ops = {'+': lambda a,b: a+b, '-': lambda a,b: a-b, '*': lambda a,b: a*b}

    def solve(expr):
        if expr in memo: return memo[expr]
        if expr.lstrip('-').isdigit(): return [int(expr)]
        res = []
        for i, c in enumerate(expr):
            if c in ops:
                for l in solve(expr[:i]):
                    for r in solve(expr[i+1:]):
                        res.append(ops[c](l, r))
        memo[expr] = res
        return res

    return solve(expression)

