def reverseList(head):
    prev = None; cur = head
    while cur:
        nxt = cur.next; cur.next = prev; prev = cur; cur = nxt
    return prev

def reverseListRec(head):
    if not head or not head.next: return head
    new_head = reverseListRec(head.next)
    head.next.next = head; head.next = None
    return new_head

def detectCycle(head):
    slow = fast = head
    while fast and fast.next:
        slow = slow.next; fast = fast.next.next
        if slow is fast:
            slow = head
            while slow is not fast: slow = slow.next; fast = fast.next
            return slow
    return None

def mergeKLists(lists):
    import heapq
    heap = []; dummy = cur = ListNode(0)
    for i, node in enumerate(lists):
        if node: heapq.heappush(heap, (node.val, i, node))
    while heap:
        val, i, node = heapq.heappop(heap)
        cur.next = node; cur = cur.next
        if node.next: heapq.heappush(heap, (node.next.val, i, node.next))
    return dummy.next

