    return dummy.next

def doubleIt(head):
    # Double linked list number: reverse, add carry, reverse back
    def reverse(node):
        prev = None
        while node: nxt = node.next; node.next = prev; prev = node; node = nxt
        return prev
    rev = reverse(head); carry = 0; cur = rev
    while cur:
        total = cur.val * 2 + carry
        cur.val = total % 10; carry = total // 10
        if not cur.next and carry:
            cur.next = ListNode(carry); carry = 0
        cur = cur.next
    return reverse(rev)

