    res = [0]*len(vals); stack = []
    for i, v in enumerate(vals):
        while stack and vals[stack[-1]] < v:
            res[stack.pop()] = v
        stack.append(i)
    return res

class LRUCache:
    def __init__(self, capacity):
        self.cap = capacity; self.cache = {}
        self.head = ListNode(0); self.tail = ListNode(0)
        self.head.next = self.tail; self.tail.prev = self.head

    def _remove(self, node):
        node.prev.next = node.next; node.next.prev = node.prev

    def _add(self, node):    # add to front (MRU position)
        node.next = self.head.next; node.prev = self.head
        self.head.next.prev = node; self.head.next = node

    def get(self, key):
        if key not in self.cache: return -1
        self._remove(self.cache[key]); self._add(self.cache[key])
        return self.cache[key].val

    def put(self, key, value):
        if key in self.cache: self._remove(self.cache[key])
        node = ListNode(value); self.cache[key] = node; self._add(node)
        if len(self.cache) > self.cap:
            lru = self.tail.prev; self._remove(lru); del self.cache[lru.key]

class MyLinkedList:
    def __init__(self): self.dummy = ListNode(0); self.size = 0

    def get(self, index):
        if index >= self.size: return -1
        cur = self.dummy
        for _ in range(index+1): cur = cur.next
        return cur.val

    def addAtHead(self, val): self.addAtIndex(0, val)
    def addAtTail(self, val): self.addAtIndex(self.size, val)

    def addAtIndex(self, index, val):
        if index > self.size: return
        cur = self.dummy
        for _ in range(index): cur = cur.next
        node = ListNode(val, cur.next); cur.next = node; self.size += 1

    def deleteAtIndex(self, index):
        if index >= self.size: return
        cur = self.dummy
        for _ in range(index): cur = cur.next
        cur.next = cur.next.next; self.size -= 1

class BrowserHistory:
