class WordDictionary:
    def __init__(self): self.root = {}

    def addWord(self, word):
        node = self.root
        for c in word: node = node.setdefault(c, {})
        node['#'] = True

    def search(self, word):
        def dfs(node, i):
            if i == len(word): return '#' in node
            c = word[i]
            if c != '.':
                return c in node and dfs(node[c], i + 1)
            return any(dfs(node[k], i + 1) for k in node if k != '#')
        return dfs(self.root, 0)

def replaceWords(dictionary, sentence):
    trie = {}
    for root in dictionary:
        node = trie
        for c in root: node = node.setdefault(c, {})
        node['#'] = root           # store shortest root at end-node

    def replace(word):
        node = trie
        for c in word:
            if c not in node: break
            node = node[c]
            if '#' in node: return node['#']   # earliest root match
        return word

    return ' '.join(replace(w) for w in sentence.split())

def findWords(board, words):
    trie = {}
    for w in words:
        node = trie
        for c in w: node = node.setdefault(c, {})
        node['#'] = w

    m, n = len(board), len(board[0])
    res = set()

    def dfs(r, c, node):
        ch = board[r][c]
        if ch not in node: return
        nxt = node[ch]
        if '#' in nxt: res.add(nxt['#'])
        board[r][c] = '#'                      # mark visited
        for dr, dc in [(0,1),(0,-1),(1,0),(-1,0)]:
            nr, nc = r+dr, c+dc
            if 0 <= nr < m and 0 <= nc < n and board[nr][nc] != '#':
                dfs(nr, nc, nxt)
        board[r][c] = ch                       # restore

    for r in range(m):
        for c in range(n):
            dfs(r, c, trie)
    return list(res)

