# Explicit rolling hash version:
def findRepeatedDnaHash(s):
    if len(s) <= 10: return []
    base = {'A':0,'C':1,'G':2,'T':3}
    B = 4; MOD = (1<<31)-1
    h = 0; pw = B**9 % MOD
    for c in s[:10]: h = (h*B + base[c]) % MOD
    seen = {h}; res = set()
    for i in range(10, len(s)):
        h = (h - base[s[i-10]] * pw % MOD + MOD) % MOD
        h = (h * B + base[s[i]]) % MOD
        if h in seen: res.add(s[i-9:i+1])
        seen.add(h)
    return list(res)

def longestCommonSubpath(n, paths):
    MOD = (1 << 61) - 1; BASE = 100003

    def get_hashes(path, length):
        if length > len(path): return set()
        h = pw = 0
        for i in range(length):
            h = (h * BASE + path[i] + 1) % MOD
        pw = pow(BASE, length - 1, MOD)
        hashes = {h}
        for i in range(1, len(path) - length + 1):
            h = (h - (path[i-1]+1) * pw % MOD + MOD) % MOD
            h = (h * BASE + path[i+length-1]+1) % MOD
            hashes.add(h)
        return hashes

    def feasible(length):
        common = get_hashes(paths[0], length)
        for p in paths[1:]:
            common &= get_hashes(p, length)
            if not common: return False
        return bool(common)

    lo, hi = 0, min(len(p) for p in paths)
    while lo < hi:
        mid = (lo + hi + 1) // 2
        if feasible(mid): lo = mid
        else: hi = mid - 1
    return lo

def z_function(s):
    n = len(s); z = [0] * n; z[0] = n
    l = r = 0
    for i in range(1, n):
        if i < r:
            z[i] = min(r - i, z[i - l])
        while i + z[i] < n and s[z[i]] == s[i + z[i]]:
            z[i] += 1
        if i + z[i] > r:
            l, r = i, i + z[i]
    return z

def pattern_match_z(text, pattern):
    # Occurrences of pattern in text
    s = pattern + '#' + text
    z = z_function(s); m = len(pattern)
    return [i - m - 1 for i in range(m + 1, len(s)) if z[i] >= m]

# Z vs KMP:
# KMP failure: lps[i] = longest proper prefix of s[:i+1] that is also a suffix
# Z-array:     z[i]   = longest match of s[i:] with s[0:]
# Both O(n); Z-function often cleaner to implement from scratch

def z_function(s):
    n = len(s); z = [0]*n; z[0]=n; l=r=0
    for i in range(1,n):
        if i<r: z[i]=min(r-i,z[i-l])
        while i+z[i]<n and s[z[i]]==s[i+z[i]]: z[i]+=1
        if i+z[i]>r: l,r=i,i+z[i]
    return z

def stringMatching(words):
    res = []
    for w in words:
        for other in words:
            if w != other:
                z = z_function(w + '#' + other)
                if any(v >= len(w) for v in z[len(w)+1:]):
                    res.append(w); break
    return res

def longestHappyPrefix(s):
