def countPairs(nums, low, high):
    # Count pairs (i<j) with low <= nums[i]^nums[j] <= high
    BITS = 15

    class Trie:
        def __init__(self): self.ch = [None, None]; self.cnt = 0

        def insert(self, x):
            cur = self
            for i in range(BITS-1, -1, -1):
                b = (x >> i) & 1
                if not cur.ch[b]: cur.ch[b] = Trie()
                cur = cur.ch[b]; cur.cnt += 1

