    return dp[n]

def aho_corasick_build(patterns):
    from collections import deque
    # Each node: {char: child_idx}, fail pointer, output set
    goto = [{}]; fail = [0]; output = [set()]
    for p in patterns:
        cur = 0
        for c in p:
            if c not in goto[cur]:
                goto.append({}); fail.append(0); output.append(set())
                goto[cur][c] = len(goto) - 1
            cur = goto[cur][c]
        output[cur].add(p)
    q = deque(goto[0].values())
    while q:
        r = q.popleft()
        for c, s in goto[r].items():
            q.append(s)
            f = fail[r]
            while f and c not in goto[f]: f = fail[f]
            fail[s] = goto[f].get(c, 0) if f else goto[0].get(c, 0)
            if fail[s] == s: fail[s] = 0
            output[s] |= output[fail[s]]
    return goto, fail, output

