def findKthNumber(n, k):
    def count_steps(n, cur, nxt):
        # Count numbers in [cur, nxt) that are <= n
        steps = 0
        while cur <= n:
            steps += min(n + 1, nxt) - cur
            cur *= 10; nxt *= 10
        return steps

    cur = 1; k -= 1
    while k > 0:
        steps = count_steps(n, cur, cur + 1)
        if steps <= k:
            # skip entire subtree rooted at cur
            k -= steps; cur += 1
        else:
