def palindromePairs(words):
    lookup = {w: i for i, w in enumerate(words)}
    res = []

    def is_pal(s): return s == s[::-1]

    for i, w in enumerate(words):
        n = len(w)
        for j in range(n + 1):
            # Case 1: w[:j] is palindrome → prepend rev(w[j:])
            if is_pal(w[:j]):
                rev = w[j:][::-1]
                if rev in lookup and lookup[rev] != i:
                    res.append([lookup[rev], i])
            # Case 2: w[j:] is palindrome → append rev(w[:j])
            if j < n and is_pal(w[j:]):
                rev = w[:j][::-1]
                if rev in lookup and lookup[rev] != i:
                    res.append([i, lookup[rev]])
    return res

