class SuffixAutomaton:
    def __init__(self):
        # Each state: len (longest), link (suffix link), next (transitions)
        self.states = [{'len': 0, 'link': -1, 'next': {}}]
        self.last = 0

    def extend(self, c):
        cur = len(self.states)
        self.states.append({'len': self.states[self.last]['len']+1, 'link':-1, 'next':{}})
        p = self.last
        while p != -1 and c not in self.states[p]['next']:
            self.states[p]['next'][c] = cur; p = self.states[p]['link']
        if p == -1:
            self.states[cur]['link'] = 0
        else:
            q = self.states[p]['next'][c]
            if self.states[p]['len'] + 1 == self.states[q]['len']:
                self.states[cur]['link'] = q
            else:
                clone = len(self.states)
                self.states.append({'len': self.states[p]['len']+1,
                                    'link': self.states[q]['link'],
                                    'next': dict(self.states[q]['next'])})
                while p != -1 and self.states[p]['next'].get(c) == q:
                    self.states[p]['next'][c] = clone; p = self.states[p]['link']
                self.states[q]['link'] = self.states[cur]['link'] = clone
        self.last = cur

