def shortestPathLength(graph):
    from collections import deque
    n = len(graph); full = (1<<n)-1
    dist = [[float('inf')]*n for _ in range(1<<n)]
    q = deque()
    for i in range(n): dist[1<<i][i] = 0; q.append((1<<i, i, 0))
    while q:
        mask, u, d = q.popleft()
        if d > dist[mask][u]: continue
        if mask == full: return d
        for v in graph[u]:
            new_mask = mask | (1<<v)
            if dist[new_mask][v] > d+1:
                dist[new_mask][v] = d+1; q.append((new_mask, v, d+1))
    return -1

