def numTilings(n):
    MOD = 10**9+7
    # dp[mask] = ways to have 'mask' as the profile (pending cells in next row)
    dp = {0: 1}
    for _ in range(n):
        new_dp = {}
        for mask, ways in dp.items():
            def fill(cur_mask, next_mask):
                if cur_mask == (1<<2)-1:
                    new_dp[next_mask] = (new_dp.get(next_mask,0) + ways) % MOD
                    return
                pos = bin(cur_mask).find('0', 2) - 2  # next 0 bit
                if cur_mask & (1<<pos):
                    fill(cur_mask|(1<<pos), next_mask)
                else:
                    # Place vertical tile
                    fill(cur_mask|(1<<pos), next_mask|(1<<pos))
                    # Place horizontal tile (need next row)
                    if pos+1 < 2 and not cur_mask&(1<<(pos+1)):
                        fill(cur_mask|(1<<pos)|(1<<(pos+1)), next_mask)
            fill(mask, 0)
        dp = new_dp
    return dp.get(0, 0)

