class LRUCache:
    class Node:
        def __init__(self,k=0,v=0): self.key=k; self.val=v; self.prev=self.next=None
    def __init__(self, capacity):
        self.cap=capacity; self.cache={}
        self.head=self.Node(); self.tail=self.Node()
        self.head.next=self.tail; self.tail.prev=self.head
    def _del(self,n): n.prev.next=n.next; n.next.prev=n.prev
    def _add(self,n): n.next=self.head.next; n.prev=self.head; self.head.next.prev=n; self.head.next=n
    def get(self,k):
        if k not in self.cache: return -1
        n=self.cache[k]; self._del(n); self._add(n); return n.val
    def put(self,k,v):
        if k in self.cache: self._del(self.cache[k])
        n=self.Node(k,v); self.cache[k]=n; self._add(n)
        if len(self.cache)>self.cap: lru=self.tail.prev; self._del(lru); del self.cache[lru.key]

class LFUCache:
    from collections import defaultdict, OrderedDict
    def __init__(self, capacity):
        self.cap=capacity; self.min_freq=0
        self.key_val={}; self.key_freq={}
        from collections import defaultdict, OrderedDict
        self.freq_keys=defaultdict(OrderedDict)
    def _update(self,k):
        f=self.key_freq[k]; del self.freq_keys[f][k]
        if not self.freq_keys[f] and f==self.min_freq: self.min_freq+=1
        self.key_freq[k]=f+1; self.freq_keys[f+1][k]=None
    def get(self,k):
        if k not in self.key_val: return -1
        self._update(k); return self.key_val[k]
    def put(self,k,v):
        if self.cap<=0: return
        if k in self.key_val: self._update(k); self.key_val[k]=v; return
        if len(self.key_val)>=self.cap:
            evict,_=self.freq_keys[self.min_freq].popitem(last=False)
            del self.key_val[evict]; del self.key_freq[evict]
        self.key_val[k]=v; self.key_freq[k]=1; self.freq_keys[1][k]=None; self.min_freq=1

