    def _find(self,t,prev):
        cur=self.head
        for i in range(self.MAX-1,-1,-1):
            while cur.next[i] and cur.next[i].val<t: cur=cur.next[i]
            prev[i]=cur
        return cur.next[0]
    def search(self,t):
        prev=[None]*self.MAX; n=self._find(t,prev); return n and n.val==t
    def add(self,v):
        import random; prev=[None]*self.MAX; self._find(v,prev)
        l=1
        while l<self.MAX and random.random()<0.5: l+=1
        n=self.Node(v,l)
        for i in range(l): n.next[i]=prev[i].next[i]; prev[i].next[i]=n
    def erase(self,v):
        prev=[None]*self.MAX; n=self._find(v,prev)
        if not n or n.val!=v: return False
        for i in range(len(n.next)):
            if prev[i].next[i] is not n: break
            prev[i].next[i]=n.next[i]
