class MKAverage:
    from sortedcontainers import SortedList
    def __init__(self,m,k):
        self.m=m; self.k=k; self.q=__import__('collections').deque()
        self.lo=__import__('sortedcontainers').SortedList()   # bottom k
        self.mid=__import__('sortedcontainers').SortedList()  # middle
        self.hi=__import__('sortedcontainers').SortedList()   # top k
        self.mid_sum=0
    def _add_to_structure(self,v):
        if len(self.lo)<self.k or v<=self.lo[-1]: self.lo.add(v)
        elif len(self.hi)<self.k or v>=self.hi[0]: self.hi.add(v)
        else: self.mid.add(v); self.mid_sum+=v
        self._rebalance()
    def _rebalance(self):
        while len(self.lo)>self.k: mv=self.lo.pop(); self.mid.add(mv); self.mid_sum+=mv
        while len(self.hi)>self.k: mv=self.hi.pop(0); self.mid.add(mv); self.mid_sum+=mv
        while self.mid and self.mid[0]<self.lo[-1]:
            mv=self.mid.pop(0); self.mid_sum-=mv; self.lo.add(mv)
        while self.mid and self.mid[-1]>self.hi[0]:
            mv=self.mid.pop(); self.mid_sum-=mv; self.hi.add(mv)
    def addElement(self,v):
        self.q.append(v); self._add_to_structure(v)
    def calculateMKAverage(self):
        if len(self.q)<self.m: return -1
        return self.mid_sum//len(self.mid) if self.mid else -1

