        if s==e: self.mn[node]=self.mx[node]=a[s]; return
        mid=(s+e)//2; self._build(a,2*node,s,mid); self._build(a,2*node+1,mid+1,e)
        self.mn[node]=min(self.mn[2*node],self.mn[2*node+1])
