class LazySegTree:
    def __init__(self,n):
        self.n=n; self.tree=[0]*(4*n); self.lazy=[0]*(4*n)
    def push_down(self,node,l,r):
        if self.lazy[node]:
            mid=(l+r)//2
            self.tree[2*node]+=(mid-l+1)*self.lazy[node]
            self.tree[2*node+1]+=(r-mid)*self.lazy[node]
            self.lazy[2*node]+=self.lazy[node]; self.lazy[2*node+1]+=self.lazy[node]
            self.lazy[node]=0
    def update(self,node,l,r,ql,qr,val):
        if qr<l or r<ql: return
        if ql<=l and r<=qr: self.tree[node]+=(r-l+1)*val; self.lazy[node]+=val; return
        self.push_down(node,l,r); mid=(l+r)//2
        self.update(2*node,l,mid,ql,qr,val); self.update(2*node+1,mid+1,r,ql,qr,val)
        self.tree[node]=self.tree[2*node]+self.tree[2*node+1]
    def query(self,node,l,r,ql,qr):
        if qr<l or r<ql: return 0
        if ql<=l and r<=qr: return self.tree[node]
        self.push_down(node,l,r); mid=(l+r)//2
        return self.query(2*node,l,mid,ql,qr)+self.query(2*node+1,mid+1,r,ql,qr)

