            mid=(l+r)//2
            self.tree[2*node]=(mid-l+1)-self.tree[2*node]; self.flip[2*node]=not self.flip[2*node]
            self.tree[2*node+1]=(r-mid)-self.tree[2*node+1]; self.flip[2*node+1]=not self.flip[2*node+1]
            self.flip[node]=False
    def flip_range(self,node,l,r,ql,qr):
        if qr<l or r<ql: return
        if ql<=l and r<=qr: self.tree[node]=(r-l+1)-self.tree[node]; self.flip[node]=not self.flip[node]; return
        self.push_down(node,l,r); mid=(l+r)//2
        self.flip_range(2*node,l,mid,ql,qr); self.flip_range(2*node+1,mid+1,r,ql,qr)
        self.tree[node]=self.tree[2*node]+self.tree[2*node+1]
    def query(self,node,l,r,ql,qr):
        if qr<l or r<ql: return 0
        if ql<=l and r<=qr: return self.tree[node]
        self.push_down(node,l,r); mid=(l+r)//2
        return self.query(2*node,l,mid,ql,qr)+self.query(2*node+1,mid+1,r,ql,qr)

