def maximumSegmentSum(nums, removeQueries):
    n=len(nums); parent=list(range(n)); sz=[0]*n; comp_sum=[0]*n
    def find(x):
        while parent[x]!=x: parent[x]=parent[parent[x]]; x=parent[x]
        return x
    def union(a,b):
        a,b=find(a),find(b)
        if a==b: return
        if sz[a]<sz[b]: a,b=b,a
        parent[b]=a; sz[a]+=sz[b]; comp_sum[a]+=comp_sum[b]
    present=[False]*n; ans=[0]*(len(removeQueries)+1)
    for i in range(len(removeQueries)-1,-1,-1):
        idx=removeQueries[i]; present[idx]=True; comp_sum[idx]=nums[idx]; sz[idx]=1
        if idx>0 and present[idx-1]: union(idx,idx-1)
        if idx<n-1 and present[idx+1]: union(idx,idx+1)
        ans[i]=comp_sum[find(idx)] if i<len(removeQueries) else 0
    return ans[:-1]

