# Segment tree accelerates DP when transition queries a range.
# Pattern: dp[i] = min/max over j in [l(i), r(i)] of f(dp[j], cost(j,i))
# Build segment tree on dp values; query range before setting dp[i]; update dp[i].
def dp_with_segtree(n, cost):
    seg=[float('inf')]*(4*n)
    def query(nd,l,r,ql,qr):
        if qr<l or r<ql: return float('inf')
        if ql<=l and r<=qr: return seg[nd]
        mid=(l+r)//2; return min(query(2*nd,l,mid,ql,qr),query(2*nd+1,mid+1,r,ql,qr))
    def update(nd,l,r,i,v):
        if l==r: seg[nd]=min(seg[nd],v); return
        mid=(l+r)//2
        if i<=mid: update(2*nd,l,mid,i,v)
        else:      update(2*nd+1,mid+1,r,i,v)
        seg[nd]=min(seg[2*nd],seg[2*nd+1])
    dp=[0]*n
    for i in range(n):
        dp[i]=query(1,0,n-1,0,i-1)+cost[i]
        update(1,0,n-1,i,dp[i])
    return dp[-1]

