    sign = '-' if (numerator < 0) ^ (denominator < 0) else ''
    n, d = abs(numerator), abs(denominator)
    integer = str(n // d); n %= d
    decimal = []; seen = {}
    while n:
        if n in seen:
            decimal.insert(seen[n], '('); decimal.append(')'); break
        seen[n] = len(decimal)
        n *= 10; decimal.append(str(n // d)); n %= d
    return sign + integer + '.' + ''.join(decimal)

