def isToeplitzMatrix(matrix):
    for r in range(1,len(matrix)):
        for c in range(1,len(matrix[0])):
            if matrix[r][c]!=matrix[r-1][c-1]: return False
    return True

def isValidSudoku(board):
    rows=[set() for _ in range(9)]; cols=[set() for _ in range(9)]; boxes=[set() for _ in range(9)]
    for r in range(9):
        for c in range(9):
            v=board[r][c]
            if v=='.': continue
            b=(r//3)*3+c//3
            if v in rows[r] or v in cols[c] or v in boxes[b]: return False
            rows[r].add(v); cols[c].add(v); boxes[b].add(v)
    return True

def rotate(matrix):
    n=len(matrix)
    for i in range(n):
        for j in range(i+1,n): matrix[i][j],matrix[j][i]=matrix[j][i],matrix[i][j]
    for row in matrix: row.reverse()

def matrixReshape(mat, r, c):
    flat=[v for row in mat for v in row]
    if len(flat)!=r*c: return mat
    return [[flat[i*c+j] for j in range(c)] for i in range(r)]

def totalNQueens(n):
    cols=set(); diag1=set(); diag2=set(); count=[0]
    def bt(row):
        if row==n: count[0]+=1; return
        for col in range(n):
            if col in cols or row-col in diag1 or row+col in diag2: continue
            cols.add(col); diag1.add(row-col); diag2.add(row+col)
            bt(row+1)
            cols.discard(col); diag1.discard(row-col); diag2.discard(row+col)
    bt(0); return count[0]

def robotSim(commands, obstacles):
    dirs=[(0,1),(1,0),(0,-1),(-1,0)]; d=0
    obs=set(map(tuple,obstacles)); x=y=best=0
    for cmd in commands:
        if cmd==-2: d=(d-1)%4
        elif cmd==-1: d=(d+1)%4
        else:
            for _ in range(cmd):
                nx,ny=x+dirs[d][0],y+dirs[d][1]
                if (nx,ny) in obs: break
                x,y=nx,ny; best=max(best,x*x+y*y)
    return best

