    res=[]; target_set=set(target); cur=0
    for t in target:
        while cur+1<t: cur+=1; res+=['Push','Pop']
        cur+=1; res.append('Push')
    return res

def isMonotonic(nums):
    inc=dec=True
    for i in range(1,len(nums)):
        if nums[i]>nums[i-1]: dec=False
        if nums[i]<nums[i-1]: inc=False
    return inc or dec

def checkPossibility(nums):
    changed=False
    for i in range(1,len(nums)):
        if nums[i]<nums[i-1]:
            if changed: return False
            changed=True
            if i>=2 and nums[i]<nums[i-2]: nums[i]=nums[i-1]
            else:                           nums[i-1]=nums[i]
    return True

def maxDistToClosest(seats):
    n=len(seats); last=-1; best=0
    for i,s in enumerate(seats):
        if s:
            if last==-1: best=i
            else:        best=max(best,(i-last)//2)
            last=i
    best=max(best,n-1-last)
    return best

def findUnsortedSubarray(nums):
    sorted_nums=sorted(nums); l=r=-1
    for i in range(len(nums)):
        if nums[i]!=sorted_nums[i]:
            if l==-1: l=i
            r=i
    return 0 if r==-1 else r-l+1

from functools import cmp_to_key
def customSortString(order, s):
    rank={c:i for i,c in enumerate(order)}
    return ''.join(sorted(s,key=lambda c:rank.get(c,len(order))))

def largestNumber(nums):
    def cmp(a,b): return -1 if a+b>b+a else (1 if a+b<b+a else 0)
    strs=sorted(map(str,nums),key=cmp_to_key(cmp))
    return '0' if strs[0]=='0' else ''.join(strs)

def countSpecial(nums):
    from collections import Counter; cnt=Counter(nums)
    return sum(1 for v,c in cnt.items() if c==v)

def numSpecial(mat):
    rows=[sum(r) for r in mat]; cols=[sum(c) for c in zip(*mat)]
    return sum(1 for r,row in enumerate(mat) for c,v in enumerate(row) if v and rows[r]==1 and cols[c]==1)

def merge(intervals):
    intervals.sort(); res=[intervals[0]]
    for s,e in intervals[1:]:
        if s<=res[-1][1]: res[-1][1]=max(res[-1][1],e)
        else:             res.append([s,e])
    return res

def insert(intervals,new):
    res=[]; i=0; n=len(intervals)
    while i<n and intervals[i][1]<new[0]: res.append(intervals[i]); i+=1
    while i<n and intervals[i][0]<=new[1]:
        new[0]=min(new[0],intervals[i][0]); new[1]=max(new[1],intervals[i][1]); i+=1
    res.append(new)
    return res+intervals[i:]

def canAttendMeetings(intervals):
    intervals.sort()
    for i in range(1,len(intervals)):
        if intervals[i][0]<intervals[i-1][1]: return False
    return True

def minMeetingRooms(intervals):
    import heapq; intervals.sort(); heap=[]
    for s,e in intervals:
        if heap and heap[0]<=s: heapq.heapreplace(heap,e)
        else:                   heapq.heappush(heap,e)
    return len(heap)

from threading import Semaphore
class Foo:
    def __init__(self): self.s1=Semaphore(0); self.s2=Semaphore(0)
    def first(self,printFirst): printFirst(); self.s1.release()
    def second(self,printSecond): self.s1.acquire(); printSecond(); self.s2.release()
    def third(self,printThird): self.s2.acquire(); printThird()

# JavaScript functional programming patterns:
# Memoize:
function memoize(fn) {
  const cache = new Map();
  return function(...args) {
    const key = JSON.stringify(args);
    if (cache.has(key)) return cache.get(key);
    const result = fn.apply(this, args);
    cache.set(key, result);
    return result;
  };
}
# Curry:
function curry(fn) {
  return function curried(...args) {
    if (args.length >= fn.length) return fn.apply(this, args);
    return function(...args2) { return curried.apply(this, args.concat(args2)); };
  };
}

def canWinNim(n):
    return n%4!=0  # Nim: if heap size divisible by 4, second player wins

def judgePoint24(cards):
    from itertools import permutations
    def check(nums):
        if len(nums)==1: return abs(nums[0]-24)<1e-6
        for i in range(len(nums)):
            for j in range(len(nums)):
                if i==j: continue
                rest=[nums[k] for k in range(len(nums)) if k!=i and k!=j]
                a,b=nums[i],nums[j]
                for val in [a+b,a-b,a*b]:
                    if check(rest+[val]): return True
                if b!=0 and check(rest+[a/b]): return True
        return False
    return check(list(map(float,cards)))
